import { useState, useEffect, useCallback, useMemo, useRef, type CSSProperties, type MouseEvent } from 'react';
import CalendarGrid, { CORE_TIME_SLOTS, type DropTarget, type MoreMenu } from './CalendarGrid';
import CalendarHeader from './CalendarHeader';
import MonthlyCalendarGrid from './MonthlyCalendarGrid';
import CalendarContextMenu from './CalendarContextMenu';
import CalendarDayContextMenu from './CalendarDayContextMenu';
import HolidayQuickModal from './HolidayQuickModal';
import Modal from './Modal';
import CalendarLegend from './CalendarLegend';
import { useToast } from '../../contexts/ToastContext';
import { useAppointmentDoctors } from '../../hooks/useAppointmentDoctors';
import {
    parseLocalDate,
    toLocalDateString,
    getWeekStartSaturday,
    addWorkingDays
} from '../../utils/calendarDate';
import { fetchJSON, postJSON, putJSON, deleteJSON, httpErrorMessage } from '@/core/http';
import * as holiday from '@shared/contracts/holiday.contract';
import * as calendar from '@shared/contracts/calendar.contract';
import type {
    ViewMode,
    CalendarMode,
    CalendarAppointment,
    CalendarDay,
    CalendarData,
    CalendarStats,
    SlotData,
    MenuPosition,
    ExistingHoliday,
    AppointmentWarning,
    SaveHolidayData
} from './calendar.types';

/* ── Density-zoom model ─────────────────────────────────────────────────────
   A single day-count N drives the Week grid. The grid already lays out
   `repeat(N, 1fr)` columns from the days array, so zoom = relayout (more/narrower
   columns) — no transform/CSS-zoom, so text stays crisp and sticky/drag keep
   working. Row height couples to N as ROW_REF/N (ROW_REF = 112 × 6), which keeps
   the default-week cell aspect ratio at every N: for board width W, colW/rowH =
   ((W−T)/N)/(ROW_REF/N) = (W−T)/ROW_REF, independent of N. Zoom out → N↑ → smaller
   cells, more days, fills the screen, fits all rows; zoom in → N↓ → fewer/bigger
   days down to one. */
const N_MIN = 1;
const N_MAX = 30;
const N_DEFAULT = 6;
const ROW_REF = 672; // 112 × 6 — the default-week reference (px)
const ROW_MIN = 44;
const ROW_MAX = 132;
const MIN_COL_W = 90; // px — Fit keeps day columns at least this wide
const N_STORAGE_KEY = 'cal-day-count';
const FETCH_DEBOUNCE_MS = 250;

const clampN = (n: number): number => Math.min(N_MAX, Math.max(N_MIN, Math.round(n)));

const rowHForN = (n: number): number =>
    Math.min(ROW_MAX, Math.max(ROW_MIN, Math.round(ROW_REF / n)));

// Font scales PROPORTIONALLY with row height (no floor) so text shrinks together
// with the rows instead of overflowing/clipping on heavy zoom-out. The natural
// minimum (~0.39) comes from the rowH clamp [44,132]; the card padding/gaps scale
// by the same factor in CSS so the whole card stays proportional.
const fontScaleForRowH = (h: number): number =>
    Math.min(1.12, Math.round((h / 112) * 100) / 100);

const readStoredDayCount = (): number => {
    try {
        const raw = localStorage.getItem(N_STORAGE_KEY);
        if (!raw) return N_DEFAULT;
        const n = Number(raw);
        return Number.isFinite(n) ? clampN(n) : N_DEFAULT;
    } catch {
        return N_DEFAULT;
    }
};

const shortDate = (d: string): string =>
    parseLocalDate(d).toLocaleDateString(undefined, {
        weekday: 'short',
        month: 'short',
        day: 'numeric'
    });

interface ContextMenuState {
    position: MenuPosition;
    appointment: CalendarAppointment;
}

interface DayContextMenuState {
    position: MenuPosition;
    day: CalendarDay;
}

interface HolidayModalState {
    date: string;
    existingHoliday: ExistingHoliday | null;
    appointmentWarning: AppointmentWarning | null;
}

interface AppointmentCalendarProps {
    initialDate?: Date | string;
    initialViewMode?: ViewMode;
    mode?: CalendarMode;
    onSlotSelect?: (slot: SlotData) => void;
    selectedSlot?: SlotData | null;
}

/**
 * AppointmentCalendar Main Component
 *
 * The primary calendar component that orchestrates all calendar functionality
 * Integrates with existing tblcalender system via optimized API endpoints
 */
const AppointmentCalendar = ({
    initialDate,
    initialViewMode = 'week',
    mode = 'view',
    onSlotSelect,
    selectedSlot: externalSelectedSlot
}: AppointmentCalendarProps) => {
    const toast = useToast();
    const { byId: doctorColors, legend: doctorLegend } = useAppointmentDoctors();

    // State management
    const [currentDate, setCurrentDate] = useState<Date>(
        initialDate ? parseLocalDate(initialDate) : new Date()
    );
    const [calendarData, setCalendarData] = useState<CalendarData | null>(null);
    const [calendarStats, setCalendarStats] = useState<CalendarStats | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [internalSelectedSlot, setInternalSelectedSlot] = useState<SlotData | null>(null);
    const [viewMode, setViewMode] = useState<ViewMode>(initialViewMode);
    const [selectedDoctorId, setSelectedDoctorId] = useState<number | null>(null);
    const [isMobile, setIsMobile] = useState(false);

    // Density-zoom: the grid window is `dayCount` working days forward from
    // `anchorDate` (the current week's Saturday at init / on Today).
    const [anchorDate, setAnchorDate] = useState<string>(() =>
        toLocalDateString(getWeekStartSaturday(initialDate ?? new Date()))
    );
    const [dayCount, setDayCount] = useState<number>(readStoredDayCount);
    const boardRef = useRef<HTMLDivElement>(null);

    // Drag-to-reschedule and "+N more" popover state
    const [draggingId, setDraggingId] = useState<string | null>(null);
    const [dropTarget, setDropTarget] = useState<DropTarget | null>(null);
    const [moreMenu, setMoreMenu] = useState<MoreMenu | null>(null);

    // Context menu and delete confirmation state
    const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
    const [deleteConfirmation, setDeleteConfirmation] = useState<CalendarAppointment | null>(null);

    // Day context menu and holiday modal state
    const [dayContextMenu, setDayContextMenu] = useState<DayContextMenuState | null>(null);
    const [holidayModal, setHolidayModal] = useState<HolidayModalState | null>(null);
    const [deleteHolidayConfirm, setDeleteHolidayConfirm] = useState<CalendarDay | null>(null);

    // Use external selected slot if provided (for controlled mode)
    const selectedSlot = externalSelectedSlot || internalSelectedSlot;

    // Mobile detection — force a single-day grid on phones.
    useEffect(() => {
        const checkMobile = () => {
            const mobile = window.innerWidth <= 768;
            setIsMobile(mobile);
            if (mobile) {
                setViewMode(prev => (prev === 'month' ? prev : 'day'));
                setDayCount(prev => (prev === 1 ? prev : 1));
            }
        };
        checkMobile();
        window.addEventListener('resize', checkMobile);
        return () => window.removeEventListener('resize', checkMobile);
    }, []);

    const validateCalendarData = (calendarResult: Partial<CalendarData> | null): CalendarData => {
        if (!calendarResult) {
            return { days: [], timeSlots: [] };
        }
        return {
            days: calendarResult.days || [],
            timeSlots: calendarResult.timeSlots || []
        };
    };

    // Cell metrics derived from N — applied as CSS vars on the root.
    const rowH = rowHForN(dayCount);
    const fontScale = fontScaleForRowH(rowH);

    // The window's last working day (inclusive).
    const gridEnd = useMemo(
        () => addWorkingDays(anchorDate, dayCount - 1),
        [anchorDate, dayCount]
    );

    // Toolbar title — main line (month + year) + sub line (range / single day).
    const titleMain = useMemo(() => {
        const base = viewMode === 'month' ? currentDate : parseLocalDate(anchorDate);
        return base.toLocaleDateString(undefined, { month: 'long', year: 'numeric' });
    }, [viewMode, currentDate, anchorDate]);

    const titleSub = useMemo(() => {
        if (viewMode === 'month') return '';
        if (dayCount === 1) {
            return parseLocalDate(anchorDate).toLocaleDateString(undefined, {
                weekday: 'long',
                month: 'long',
                day: 'numeric',
                year: 'numeric'
            });
        }
        return `${shortDate(anchorDate)} – ${shortDate(gridEnd)} · ${dayCount} days`;
    }, [viewMode, dayCount, anchorDate, gridEnd]);

    const rangeLabel = titleSub || titleMain;

    // ── Data fetching ───────────────────────────────────────────────────────
    // Grid (day/week/zoom): one round-trip to /range returns days + timeSlots + stats.
    const fetchGrid = useCallback(
        async (anchor: string, n: number, doctorId: number | null) => {
            setLoading(true);
            setError(null);
            try {
                const start = anchor;
                const end = addWorkingDays(anchor, n - 1);
                const params = new URLSearchParams({ start, end });
                if (doctorId) params.append('doctorId', String(doctorId));

                const result = await fetchJSON<{
                    days?: CalendarData['days'];
                    timeSlots?: string[];
                    stats?: CalendarStats;
                }>(`/api/calendar/range?${params}`, { schema: calendar.range.response });

                setCalendarData({ days: result.days ?? [], timeSlots: result.timeSlots ?? [] });
                setCalendarStats(result.stats ?? null);
            } catch (err) {
                console.error('❌ Calendar range fetch error:', err);
                setError(httpErrorMessage(err, 'Unknown error'));
                setCalendarData(null);
                setCalendarStats(null);
            } finally {
                setLoading(false);
            }
        },
        []
    );

    // Month view keeps its own endpoints (separate summary grid).
    const fetchMonth = useCallback(
        async (date: Date, doctorId: number | null) => {
            setLoading(true);
            setError(null);
            try {
                const targetDate = toLocalDateString(date);
                const params = new URLSearchParams({ date: targetDate });
                if (doctorId) params.append('doctorId', String(doctorId));

                const [monthResult, statsResult] = await Promise.all([
                    fetchJSON<Partial<CalendarData>>(`/api/calendar/month?${params}`, {
                        schema: calendar.month.response
                    }),
                    fetchJSON<{ stats?: CalendarStats }>(
                        `/api/calendar/stats?date=${targetDate}`,
                        { schema: calendar.stats.response }
                    )
                ]);

                setCalendarData(validateCalendarData(monthResult));
                setCalendarStats(statsResult.stats ?? null);
            } catch (err) {
                console.error('❌ Calendar month fetch error:', err);
                setError(httpErrorMessage(err, 'Unknown error'));
                setCalendarData(null);
                setCalendarStats(null);
            } finally {
                setLoading(false);
            }
        },
        []
    );

    // Refetch the active view (used after reschedule/delete/holiday mutations).
    const refetch = useCallback(
        () =>
            viewMode === 'month'
                ? fetchMonth(currentDate, selectedDoctorId)
                : fetchGrid(anchorDate, dayCount, selectedDoctorId),
        [viewMode, currentDate, anchorDate, dayCount, selectedDoctorId, fetchMonth, fetchGrid]
    );

    // ── Navigation ──────────────────────────────────────────────────────────
    const navigate = useCallback(
        (direction: 'next' | 'prev') => {
            if (viewMode === 'month') {
                setCurrentDate(prev => {
                    const d = new Date(prev);
                    d.setMonth(d.getMonth() + (direction === 'next' ? 1 : -1));
                    return d;
                });
                return;
            }
            // Page the anchor by exactly the visible span (gap-free, forward-extend).
            setAnchorDate(prev =>
                addWorkingDays(prev, direction === 'next' ? dayCount : -dayCount)
            );
        },
        [viewMode, dayCount]
    );

    const goToToday = useCallback(() => {
        const today = new Date();
        setCurrentDate(today);
        setAnchorDate(toLocalDateString(getWeekStartSaturday(today)));
    }, []);

    // Set the column count and keep the segmented control in sync (1 → Day).
    const applyDayCount = useCallback((next: number) => {
        const n = clampN(next);
        setDayCount(n);
        setViewMode(n === 1 ? 'day' : 'week');
    }, []);

    // Zoom: in = fewer/bigger days, out = more/smaller days.
    const handleZoomIn = useCallback(() => applyDayCount(dayCount - 1), [applyDayCount, dayCount]);
    const handleZoomOut = useCallback(() => applyDayCount(dayCount + 1), [applyDayCount, dayCount]);
    const handleZoomSlider = useCallback((n: number) => applyDayCount(n), [applyDayCount]);

    // Fit: largest cells that still show every configured time row, columns kept
    // readable. Row count comes from the live time slots (falls back to the
    // hardcoded set before the first load).
    const handleZoomFit = useCallback(() => {
        const board = boardRef.current;
        if (!board) return;
        const headers = board.querySelector<HTMLElement>('.cal-day-headers');
        const headerH = headers?.getBoundingClientRect().height ?? 0;
        const availH = board.clientHeight - headerH - 4;
        const timeW =
            parseFloat(getComputedStyle(board).getPropertyValue('--cal-grid-time-w')) || 70;
        const availW = board.clientWidth - timeW;
        if (availH <= 0 || availW <= 0) return;
        const rowCount = calendarData?.timeSlots?.length || CORE_TIME_SLOTS.length;
        const byHeight = Math.ceil((rowCount * ROW_REF) / availH);
        const byWidth = Math.floor(availW / MIN_COL_W);
        applyDayCount(Math.min(byHeight, byWidth));
    }, [applyDayCount, calendarData]);

    // ── View mode ───────────────────────────────────────────────────────────
    const handleViewModeChange = useCallback(
        (newViewMode: ViewMode) => {
            if (isMobile && newViewMode !== 'day') return;

            if (newViewMode === 'month') {
                // Open the month containing the current grid anchor.
                setCurrentDate(parseLocalDate(anchorDate));
                setViewMode('month');
                return;
            }

            // Leaving month → re-anchor the grid on the visible month.
            if (viewMode === 'month') {
                setAnchorDate(toLocalDateString(getWeekStartSaturday(currentDate)));
            }
            setViewMode(newViewMode);
            setDayCount(newViewMode === 'day' ? 1 : N_DEFAULT);
        },
        [isMobile, viewMode, currentDate, anchorDate]
    );

    const handleDoctorChange = useCallback((doctorId: number | null) => {
        setSelectedDoctorId(doctorId);
    }, []);

    const handleReschedule = useCallback(
        async (
            appointmentID: number | string,
            newDate: string,
            newTime: string,
            appt: CalendarAppointment
        ) => {
            const personID = appt.personID ?? appt.person_id;
            if (!personID || !appt.drID || !appt.appDetail) {
                toast.error('Cannot reschedule: appointment is missing required details');
                return;
            }

            try {
                await putJSON(`/api/appointments/${appointmentID}`, {
                    person_id: personID,
                    dr_id: appt.drID,
                    app_detail: appt.appDetail,
                    app_date: `${newDate}T${newTime}:00`
                });

                toast.success('Appointment rescheduled');
                await refetch();
            } catch (error) {
                toast.error(httpErrorMessage(error, 'Failed to reschedule appointment'));
            }
        },
        [refetch, toast]
    );

    const handleSlotClick = useCallback((slot: SlotData, _event: MouseEvent<HTMLDivElement>) => {
        if (mode === 'selection') {
            // In selection mode, only allow selecting available slots
            if (slot.slotStatus !== 'available') {
                return;
            }

            // Update internal state if no external control
            if (!externalSelectedSlot) {
                setInternalSelectedSlot(slot);
            }

            // Call external selection handler
            if (onSlotSelect) {
                onSlotSelect(slot);
            }
        } else {
            // View mode: appointments are managed via their individual cards
            // (handleAppointmentClick) or the "+N more" overflow popover. A bare
            // slot click only updates highlighting — no redundant picker list.
            setInternalSelectedSlot(slot);
        }
    }, [mode, externalSelectedSlot, onSlotSelect]);

    // Clicking a specific appointment card goes straight to its Edit/Delete
    // menu — each card is individually rendered, so there's no list to pick from.
    const handleAppointmentClick = useCallback((
        appt: CalendarAppointment,
        date: string,
        time: string,
        event: MouseEvent<HTMLDivElement>
    ) => {
        // Card clicks are for managing existing appointments; selection mode
        // books empty slots, so ignore them there.
        if (mode === 'selection') return;

        // Block edits/deletes on past appointments, matching slot-click behaviour.
        if (new Date(`${date}T${time}:00`) < new Date()) {
            toast.error('You cannot edit or delete past appointments');
            return;
        }

        setContextMenu({
            position: { x: event.clientX, y: event.clientY },
            appointment: appt
        });
    }, [mode, toast]);

    // Handler for clicking on a day in monthly view
    const handleDayClick = useCallback((day: CalendarDay) => {
        // Switch to a single-day grid for the selected day
        setAnchorDate(day.date);
        setDayCount(1);
        setViewMode('day');
    }, []);

    // Handler for right-clicking on a day in monthly view (holiday management)
    const handleDayContextMenu = useCallback((day: CalendarDay, event: MouseEvent<HTMLDivElement>) => {
        setDayContextMenu({
            position: { x: event.clientX, y: event.clientY },
            day
        });
    }, []);

    // Close day context menu
    const handleCloseDayContextMenu = useCallback(() => {
        setDayContextMenu(null);
    }, []);

    // Add holiday from context menu
    const handleAddHoliday = useCallback(async (day: CalendarDay) => {
        // Check for existing appointments on this date
        try {
            const data = await fetchJSON<AppointmentWarning>(
                `/api/holidays/appointments-on-date?date=${day.date}`,
                { schema: holiday.appointmentsOnDate.response }
            );

            setHolidayModal({
                date: day.date,
                existingHoliday: null,
                appointmentWarning: data.count > 0 ? data : null
            });
        } catch {
            // If check fails, still allow adding holiday
            setHolidayModal({
                date: day.date,
                existingHoliday: null,
                appointmentWarning: null
            });
        }
    }, []);

    // Edit holiday from context menu
    const handleEditHoliday = useCallback((day: CalendarDay) => {
        setHolidayModal({
            date: day.date,
            existingHoliday: {
                ID: day.holidayId,
                HolidayName: day.holidayName,
                Description: day.holidayDescription
            },
            appointmentWarning: null
        });
    }, []);

    // Remove holiday from context menu
    const handleRemoveHoliday = useCallback((day: CalendarDay) => {
        setDeleteHolidayConfirm(day);
    }, []);

    // Close holiday modal
    const handleCloseHolidayModal = useCallback(() => {
        setHolidayModal(null);
    }, []);

    // Save holiday (add or update)
    const handleSaveHoliday = useCallback(async ({ date, holidayName, description, existingId }: SaveHolidayData) => {
        try {
            const isEdit = !!existingId;
            const body = {
                holiday_date: date,
                holiday_name: holidayName,
                description: description
            };

            if (isEdit) {
                await putJSON(`/api/admin/lookups/tblHolidays/${existingId}`, body);
            } else {
                await postJSON('/api/admin/lookups/tblHolidays', body);
            }

            toast.success(isEdit ? 'Holiday updated' : 'Holiday added');
            setHolidayModal(null);

            // Refresh calendar to show updated holidays
            await refetch();
        } catch (error) {
            toast.error(httpErrorMessage(error, 'Failed to save holiday'));
        }
    }, [refetch, toast]);

    // Confirm delete holiday
    const handleDeleteHolidayConfirm = useCallback(async () => {
        if (!deleteHolidayConfirm?.holidayId) return;

        try {
            await deleteJSON(`/api/admin/lookups/tblHolidays/${deleteHolidayConfirm.holidayId}`);

            toast.success('Holiday removed');
            setDeleteHolidayConfirm(null);

            // Refresh calendar
            await refetch();
        } catch (error) {
            toast.error(httpErrorMessage(error, 'Failed to remove holiday'));
        }
    }, [deleteHolidayConfirm, refetch, toast]);

    // Handler for delete action from context menu
    const handleDeleteRequest = useCallback((appointment: CalendarAppointment) => {
        setDeleteConfirmation(appointment);
    }, []);

    // Handler for confirmed delete
    const handleDeleteConfirm = useCallback(async () => {
        if (!deleteConfirmation?.appointment_id) return;

        try {
            await deleteJSON(`/api/appointments/${deleteConfirmation.appointment_id}`);

            // Refresh calendar data after successful delete
            await refetch();

            // Close delete confirmation modal
            setDeleteConfirmation(null);
        } catch (error) {
            console.error('Error deleting appointment:', error);
            toast.error('Failed to delete appointment: ' + httpErrorMessage(error, 'Unknown error'));
        }
    }, [deleteConfirmation, refetch, toast]);

    // Handler to close context menu
    const handleCloseContextMenu = useCallback(() => {
        setContextMenu(null);
    }, []);

    // Effects
    // Month fetches immediately; grid fetches are debounced so dragging the zoom
    // slider through several N values issues one request, not one per step.
    useEffect(() => {
        if (viewMode === 'month') {
            fetchMonth(currentDate, selectedDoctorId);
            return;
        }
        const t = setTimeout(
            () => fetchGrid(anchorDate, dayCount, selectedDoctorId),
            FETCH_DEBOUNCE_MS
        );
        return () => clearTimeout(t);
    }, [viewMode, currentDate, anchorDate, dayCount, selectedDoctorId, fetchGrid, fetchMonth]);

    // Persist the zoom (day count) per-browser.
    useEffect(() => {
        try {
            localStorage.setItem(N_STORAGE_KEY, String(dayCount));
        } catch {
            // Ignore storage failures (private mode / quota).
        }
    }, [dayCount]);

    // Loading state — only the initial load replaces the grid with a spinner;
    // refetches (nav, zoom, mutations) keep the current grid visible.
    if (loading && !calendarData) {
        return (
            <div className="appointment-calendar loading">
                <div className="calendar-loading">
                    <div className="loading-spinner">
                        <i className="fas fa-spinner fa-spin"></i>
                    </div>
                    <h3>Loading Calendar...</h3>
                    <p>Fetching appointment data for {rangeLabel}</p>
                </div>
            </div>
        );
    }

    // Error state
    if (error) {
        return (
            <div className="appointment-calendar error">
                <div className="calendar-error">
                    <i className="fas fa-exclamation-triangle"></i>
                    <h3>Calendar Loading Error</h3>
                    <p className="error-message">{error}</p>
                    <div className="error-actions">
                        <button
                            className="btn btn-primary"
                            onClick={() => refetch()}
                        >
                            <i className="fas fa-refresh"></i>
                            Retry
                        </button>
                        <button
                            className="btn btn-secondary"
                            onClick={goToToday}
                        >
                            <i className="fas fa-calendar-day"></i>
                            Go to Today
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    // Main render
    return (
        <div
            className="appointment-calendar"
            style={{ '--cal-row-h': `${rowH}px`, '--cal-font-scale': fontScale } as CSSProperties}
        >
            {/* Calendar Header */}
            <CalendarHeader
                titleMain={titleMain}
                titleSub={titleSub}
                onPreviousWeek={() => navigate('prev')}
                onNextWeek={() => navigate('next')}
                onTodayClick={goToToday}
                viewMode={viewMode}
                onViewModeChange={handleViewModeChange}
                calendarStats={calendarStats}
                loading={loading}
                selectedDoctorId={selectedDoctorId}
                onDoctorChange={handleDoctorChange}
                showZoom={viewMode !== 'month' && !isMobile}
                dayCount={dayCount}
                minDayCount={N_MIN}
                maxDayCount={N_MAX}
                onZoomIn={handleZoomIn}
                onZoomOut={handleZoomOut}
                onZoomSlider={handleZoomSlider}
                onZoomFit={handleZoomFit}
            />

            {/* Doctor colour legend (week/day views only — month cells aren't tinted) */}
            {viewMode !== 'month' && <CalendarLegend doctors={doctorLegend} />}

            {/* Calendar Grid - Show different grid based on view mode */}
            {viewMode === 'month' ? (
                <MonthlyCalendarGrid
                    calendarData={calendarData}
                    onDayClick={handleDayClick}
                    onDayContextMenu={handleDayContextMenu}
                    currentDate={currentDate}
                    mode={mode}
                />
            ) : (
                <CalendarGrid
                    calendarData={calendarData}
                    doctorColors={doctorColors}
                    hideEmptySlots={selectedDoctorId != null}
                    selectedSlot={selectedSlot}
                    onSlotClick={handleSlotClick}
                    onAppointmentClick={handleAppointmentClick}
                    onDayContextMenu={handleDayContextMenu}
                    mode={mode}
                    viewMode={viewMode}
                    draggingId={draggingId}
                    setDraggingId={setDraggingId}
                    dropTarget={dropTarget}
                    setDropTarget={setDropTarget}
                    moreMenu={moreMenu}
                    setMoreMenu={setMoreMenu}
                    onReschedule={handleReschedule}
                    boardRef={boardRef}
                />
            )}

            {/* Context Menu */}
            {contextMenu && (
                <CalendarContextMenu
                    position={contextMenu.position}
                    appointment={contextMenu.appointment}
                    onClose={handleCloseContextMenu}
                    onDelete={handleDeleteRequest}
                />
            )}

            {/* Delete Confirmation Modal */}
            <Modal
                isOpen={deleteConfirmation !== null}
                onClose={() => setDeleteConfirmation(null)}
                contentClassName="modal-content delete-modal"
                ariaLabelledBy="appt-delete-modal-title"
            >
                {deleteConfirmation && (
                    <>
                        <h3 id="appt-delete-modal-title">
                            <i className="fas fa-exclamation-triangle"></i> Confirm Delete
                        </h3>
                        <p>
                            Are you sure you want to delete the appointment for{' '}
                            <strong>{deleteConfirmation.patientName || 'this patient'}</strong>
                            {deleteConfirmation.appDetail && ` (${deleteConfirmation.appDetail})`}?
                        </p>
                        <div className="modal-actions">
                            <button
                                className="btn btn-cancel"
                                onClick={() => setDeleteConfirmation(null)}
                            >
                                Cancel
                            </button>
                            <button
                                className="btn btn-delete"
                                onClick={handleDeleteConfirm}
                            >
                                <i className="fas fa-trash"></i> Delete
                            </button>
                        </div>
                    </>
                )}
            </Modal>

            {/* Day Context Menu (for holiday management) */}
            {dayContextMenu && (
                <CalendarDayContextMenu
                    position={dayContextMenu.position}
                    day={dayContextMenu.day}
                    onClose={handleCloseDayContextMenu}
                    onAddHoliday={handleAddHoliday}
                    onEditHoliday={handleEditHoliday}
                    onRemoveHoliday={handleRemoveHoliday}
                />
            )}

            {/* Holiday Quick Modal */}
            <HolidayQuickModal
                isOpen={!!holidayModal}
                onClose={handleCloseHolidayModal}
                onSave={handleSaveHoliday}
                date={holidayModal?.date}
                existingHoliday={holidayModal?.existingHoliday}
                appointmentWarning={holidayModal?.appointmentWarning}
            />

            {/* Delete Holiday Confirmation Modal */}
            <Modal
                isOpen={deleteHolidayConfirm !== null}
                onClose={() => setDeleteHolidayConfirm(null)}
                contentClassName="modal-content delete-modal"
                ariaLabelledBy="holiday-delete-modal-title"
            >
                {deleteHolidayConfirm && (
                    <>
                        <h3 id="holiday-delete-modal-title">
                            <i className="fas fa-exclamation-triangle"></i> Remove Holiday
                        </h3>
                        <p>
                            Are you sure you want to remove{' '}
                            <strong>{deleteHolidayConfirm.holidayName || 'this holiday'}</strong>?
                        </p>
                        <p className="text-muted">
                            This will allow appointments to be scheduled on this date again.
                        </p>
                        <div className="modal-actions">
                            <button
                                className="btn btn-cancel"
                                onClick={() => setDeleteHolidayConfirm(null)}
                            >
                                Cancel
                            </button>
                            <button
                                className="btn btn-delete"
                                onClick={handleDeleteHolidayConfirm}
                            >
                                <i className="fas fa-trash"></i> Remove Holiday
                            </button>
                        </div>
                    </>
                )}
            </Modal>
        </div>
    );
};

export default AppointmentCalendar;

import React, { useState, useEffect, useRef, ChangeEvent, FormEvent, MouseEvent } from 'react';
import Modal from './Modal';
import { useToast } from '../../contexts/ToastContext';
import { useConfirm } from '../../contexts/ConfirmContext';
import type { AlignerBatch, AlignerSetForBatch } from '../../pages/aligner/aligner.types';
import { formatISODate } from '../../core/utils';
import { postJSON, putJSON, patchJSON, httpErrorMessage, type HttpError } from '@/core/http';

interface BatchFormData {
    batch_sequence: number | string;
    upper_aligner_count: number | string;
    lower_aligner_count: number | string;
    days: number | string;
    notes: string;
    is_active: boolean;
    is_last: boolean;
}

interface ComputedFields {
    upper_aligner_start_sequence: number;
    lower_aligner_start_sequence: number;
    upper_aligner_end_sequence: number | null;
    lower_aligner_end_sequence: number | null;
}

interface FormErrors {
    batch_sequence?: string;
    upper_aligner_count?: string;
    lower_aligner_count?: string;
    is_active?: string;
    is_last?: string;
    [key: string]: string | undefined;
}

interface BatchFormDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: () => Promise<void>;
    batch?: AlignerBatch | null;
    set?: AlignerSetForBatch | null;
    existingBatches?: AlignerBatch[];
    onUndoManufacture?: (batch: AlignerBatch, e: MouseEvent<HTMLButtonElement>) => void;
    onUndoDelivery?: (batch: AlignerBatch, e: MouseEvent<HTMLButtonElement>) => void;
}

const BatchFormDrawer: React.FC<BatchFormDrawerProps> = ({
    isOpen,
    onClose,
    onSave,
    batch,
    set,
    existingBatches = [],
    onUndoManufacture,
    onUndoDelivery
}) => {
    const toast = useToast();
    const confirm = useConfirm();
    const [formData, setFormData] = useState<BatchFormData>({
        batch_sequence: '',
        upper_aligner_count: '',
        lower_aligner_count: '',
        days: '',
        notes: '',
        is_active: false,
        is_last: false
    });

    // State for date editing
    const [editingManufactureDate, setEditingManufactureDate] = useState<boolean>(false);
    const [editingDeliveryDate, setEditingDeliveryDate] = useState<boolean>(false);
    const [tempManufactureDate, setTempManufactureDate] = useState<string>('');
    const [tempDeliveryDate, setTempDeliveryDate] = useState<string>('');
    const [savingDate, setSavingDate] = useState<boolean>(false);

    const [computedFields, setComputedFields] = useState<ComputedFields>({
        upper_aligner_start_sequence: 1,
        lower_aligner_start_sequence: 1,
        upper_aligner_end_sequence: null,
        lower_aligner_end_sequence: null
    });

    const [errors, setErrors] = useState<FormErrors>({});
    const [saving, setSaving] = useState<boolean>(false);
    const previousIsOpenRef = useRef<boolean>(false);

    // Template option - only for first batch (when no existing batches OR editing the first batch)
    // Separate controls for upper and lower
    const [hasUpperTemplate, setHasUpperTemplate] = useState<boolean>(true);
    const [hasLowerTemplate, setHasLowerTemplate] = useState<boolean>(true);
    const isFirstBatch = existingBatches.length === 0;
    // When editing, check if this batch is the first one (no other batch has a lower sequence)
    const isEditingFirstBatch = batch && !existingBatches.some(b =>
        b.aligner_batch_id !== batch.aligner_batch_id && b.batch_sequence < batch.batch_sequence
    );
    const canChangeTemplateOption = isFirstBatch || isEditingFirstBatch;

    useEffect(() => {
        // Only run when drawer opens (isOpen transitions from false to true)
        if (isOpen && !previousIsOpenRef.current) {
            if (batch) {
                // Edit mode - populate form (dates are handled separately via status endpoints)
                setFormData({
                    batch_sequence: batch.batch_sequence ?? '',
                    upper_aligner_count: batch.upper_aligner_count ?? '',
                    lower_aligner_count: batch.lower_aligner_count ?? '',
                    days: batch.days ?? '',
                    notes: batch.notes || '',
                    is_active: batch.is_active !== undefined ? batch.is_active : false,
                    is_last: batch.is_last !== undefined ? batch.is_last : false
                });
                // Reset date editing state
                setEditingManufactureDate(false);
                setEditingDeliveryDate(false);
                setTempManufactureDate('');
                setTempDeliveryDate('');
                setComputedFields({
                    upper_aligner_start_sequence: batch.upper_aligner_start_sequence ?? 1,
                    lower_aligner_start_sequence: batch.lower_aligner_start_sequence ?? 1,
                    upper_aligner_end_sequence: batch.upper_aligner_end_sequence ?? null,
                    lower_aligner_end_sequence: batch.lower_aligner_end_sequence ?? null
                });
                // When editing first batch, read template flags directly from the batch
                const isFirstBatchEdit = !existingBatches.some(b =>
                    b.aligner_batch_id !== batch.aligner_batch_id && b.batch_sequence < batch.batch_sequence
                );
                if (isFirstBatchEdit) {
                    setHasUpperTemplate(batch.has_upper_template ?? false);
                    setHasLowerTemplate(batch.has_lower_template ?? false);
                }
            } else {
                // Add mode - calculate next batch sequence and start sequences
                const nextBatchSequence = existingBatches.length > 0
                    ? Math.max(...existingBatches.map(b => b.batch_sequence || 0)) + 1
                    : 1;

                // Calculate start sequences based on last batch's end sequences
                let upperStart = 1;
                let lowerStart = 1;

                if (existingBatches.length > 0) {
                    const lastBatch = existingBatches.reduce((latest, b) =>
                        (b.batch_sequence > latest.batch_sequence) ? b : latest
                    );

                    upperStart = (lastBatch.upper_aligner_end_sequence || 0) + 1;
                    lowerStart = (lastBatch.lower_aligner_end_sequence || 0) + 1;
                }
                // First batch defaults to start=1 (no template); the template effect below
                // shifts it to 0 if the user enables HasUpperTemplate/HasLowerTemplate.

                setFormData({
                    batch_sequence: nextBatchSequence,
                    upper_aligner_count: '',
                    lower_aligner_count: '',
                    days: set?.days || '',
                    notes: '',
                    is_active: false,
                    is_last: false
                });
                // Reset date editing state for add mode
                setEditingManufactureDate(false);
                setEditingDeliveryDate(false);
                setTempManufactureDate('');
                setTempDeliveryDate('');

                setComputedFields({
                    upper_aligner_start_sequence: upperStart,
                    lower_aligner_start_sequence: lowerStart,
                    upper_aligner_end_sequence: null,
                    lower_aligner_end_sequence: null
                });

                // Default template flags to false for new batches (user can opt in on first batch)
                setHasUpperTemplate(false);
                setHasLowerTemplate(false);
            }
            setErrors({});
        }

        previousIsOpenRef.current = isOpen;
    }, [isOpen, batch, existingBatches, set?.days]);

    // Update start sequences when template flag checkboxes change (for first batch - add or edit)
    useEffect(() => {
        if (canChangeTemplateOption) {
            setComputedFields(prev => ({
                ...prev,
                upper_aligner_start_sequence: hasUpperTemplate ? 0 : 1,
                lower_aligner_start_sequence: hasLowerTemplate ? 0 : 1
            }));
        }
    }, [hasUpperTemplate, hasLowerTemplate, canChangeTemplateOption]);

    // Auto-calculate end sequences when counts change
    useEffect(() => {
        const upperCount = parseInt(String(formData.upper_aligner_count));
        const lowerCount = parseInt(String(formData.lower_aligner_count));

        setComputedFields(prev => ({
            ...prev,
            upper_aligner_end_sequence: !isNaN(upperCount) && upperCount > 0
                ? prev.upper_aligner_start_sequence + upperCount - 1
                : null,
            lower_aligner_end_sequence: !isNaN(lowerCount) && lowerCount > 0
                ? prev.lower_aligner_start_sequence + lowerCount - 1
                : null
        }));
    }, [formData.upper_aligner_count, formData.lower_aligner_count]);

    const handleChange = (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>): void => {
        const { name, value, type } = e.target;
        const checked = (e.target as HTMLInputElement).checked;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
        // Clear error for this field
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: undefined }));
        }
    };

    const validate = (): { valid: boolean; errors: FormErrors } => {
        const newErrors: FormErrors = {};

        if (!formData.batch_sequence || formData.batch_sequence === '') {
            newErrors.batch_sequence = 'Batch sequence is required';
        }

        // Validate active batch must have delivery date (check batch prop, not formData)
        if (formData.is_active && !batch?.delivered_to_patient_date) {
            newErrors.is_active = 'Cannot mark as active: batch must be delivered first';
        }

        // Real aligners consumed = total slots in batch minus the template slot (if any).
        // Only the first batch can carry a template; non-first batches ignore the flag.
        const newHasUpperTpl = canChangeTemplateOption && hasUpperTemplate;
        const newHasLowerTpl = canChangeTemplateOption && hasLowerTemplate;

        // Validate upper aligner consumption doesn't exceed remaining
        if (set && formData.upper_aligner_count) {
            const upperCount = parseInt(String(formData.upper_aligner_count));
            const upperConsumed = upperCount - (newHasUpperTpl ? 1 : 0);
            // When editing, add back this batch's prior real consumption to get available total
            const oldUpperCount = batch ? (parseInt(String(batch.upper_aligner_count)) || 0) : 0;
            const oldUpperConsumed = batch ? oldUpperCount - (batch.has_upper_template ? 1 : 0) : 0;
            const availableUpper = (set.remaining_upper_aligners || 0) + oldUpperConsumed;

            if (!isNaN(upperCount) && upperConsumed > availableUpper) {
                newErrors.upper_aligner_count = `Cannot exceed ${availableUpper} available upper aligners (${set.remaining_upper_aligners} remaining + ${oldUpperConsumed} from this batch)`;
            }
        }

        // Validate lower aligner consumption doesn't exceed remaining
        if (set && formData.lower_aligner_count) {
            const lowerCount = parseInt(String(formData.lower_aligner_count));
            const lowerConsumed = lowerCount - (newHasLowerTpl ? 1 : 0);
            const oldLowerCount = batch ? (parseInt(String(batch.lower_aligner_count)) || 0) : 0;
            const oldLowerConsumed = batch ? oldLowerCount - (batch.has_lower_template ? 1 : 0) : 0;
            const availableLower = (set.remaining_lower_aligners || 0) + oldLowerConsumed;

            if (!isNaN(lowerCount) && lowerConsumed > availableLower) {
                newErrors.lower_aligner_count = `Cannot exceed ${availableLower} available lower aligners (${set.remaining_lower_aligners} remaining + ${oldLowerConsumed} from this batch)`;
            }
        }

        setErrors(newErrors);
        return { valid: Object.keys(newErrors).length === 0, errors: newErrors };
    };

    const handleSubmit = async (e: FormEvent<HTMLFormElement>): Promise<void> => {
        e.preventDefault();

        const validation = validate();
        if (!validation.valid) {
            // Show toast for validation errors so user knows what went wrong
            const errorMessages = Object.values(validation.errors).filter(Boolean);
            if (errorMessages.length > 0) {
                toast.error(errorMessages[0] as string);
            } else {
                toast.error('Please fix the form errors before saving');
            }
            return;
        }

        // Check if remaining aligners would hit 0 after this save.
        // Use real aligner consumption (total slots minus template slot), not raw counts.
        const newHasUpperTpl = canChangeTemplateOption && hasUpperTemplate;
        const newHasLowerTpl = canChangeTemplateOption && hasLowerTemplate;

        const upperCount = parseInt(String(formData.upper_aligner_count)) || 0;
        const lowerCount = parseInt(String(formData.lower_aligner_count)) || 0;
        const newUpperConsumed = upperCount - (newHasUpperTpl ? 1 : 0);
        const newLowerConsumed = lowerCount - (newHasLowerTpl ? 1 : 0);

        const oldUpperCount = batch ? (parseInt(String(batch.upper_aligner_count)) || 0) : 0;
        const oldLowerCount = batch ? (parseInt(String(batch.lower_aligner_count)) || 0) : 0;
        const oldUpperConsumed = batch ? oldUpperCount - (batch.has_upper_template ? 1 : 0) : 0;
        const oldLowerConsumed = batch ? oldLowerCount - (batch.has_lower_template ? 1 : 0) : 0;

        const newRemainingUpper = (set?.remaining_upper_aligners ?? 0) + oldUpperConsumed - newUpperConsumed;
        const newRemainingLower = (set?.remaining_lower_aligners ?? 0) + oldLowerConsumed - newLowerConsumed;

        let markAsLast = false;
        if (newRemainingUpper === 0 && newRemainingLower === 0 && !formData.is_last) {
            markAsLast = await confirm(
                'Both remaining upper and lower aligners will be 0. Do you want to mark this as the last batch?',
                { title: 'Mark as Last Batch', confirmText: 'Mark as Last', cancelText: 'No' }
            );
        }

        setSaving(true);

        try {
            const dataToSend = {
                ...formData,
                ...(markAsLast && { is_last: true }),
                aligner_set_id: set?.aligner_set_id,
                upper_aligner_start_sequence: computedFields.upper_aligner_start_sequence,
                lower_aligner_start_sequence: computedFields.lower_aligner_start_sequence,
                has_upper_template: canChangeTemplateOption ? hasUpperTemplate : undefined,
                has_lower_template: canChangeTemplateOption ? hasLowerTemplate : undefined
            };

            const url = batch
                ? `/api/aligner/batches/${batch.aligner_batch_id}`
                : '/api/aligner/batches';

            // Flat { success, …, deactivatedBatch? } (no `data` key) → passthrough; a
            // non-2xx (400/500) now throws and is handled in the catch.
            const result = batch
                ? await putJSON<{ deactivatedBatch?: { batchSequence: number } }>(url, dataToSend)
                : await postJSON<{ deactivatedBatch?: { batchSequence: number } }>(url, dataToSend);

            // Show success message
            toast.success(batch ? 'Batch updated successfully!' : 'Batch created successfully!');

            // If a batch was automatically deactivated, inform the user
            if (result.deactivatedBatch && formData.is_active) {
                toast.info(`Batch #${result.deactivatedBatch.batchSequence} was automatically deactivated (only one batch can be active at a time)`);
            }

            await onSave();
            onClose();
        } catch (error) {
            console.error('Error saving batch:', error);
            // Preserve the old precedence: details.message → error → message → fallback,
            // now read off the thrown HttpError's parsed body.
            const data = (error as HttpError).data as
                | { error?: string; message?: string; details?: { message?: string } }
                | undefined;
            const errorMessage = data?.details?.message || data?.error || data?.message || 'Failed to save batch';
            toast.error(errorMessage);
        } finally {
            setSaving(false);
        }
    };

    const getTodayDateString = (): string => {
        return formatISODate();
    };

    const formatDisplayDate = (dateStr: string | null | undefined): string => {
        if (!dateStr) return 'Not set';
        return new Date(dateStr).toLocaleDateString('en-GB', {
            year: 'numeric', month: 'short', day: 'numeric'
        });
    };

    // Handle date changes via status endpoints
    const handleSetManufactureDate = async (dateStr: string): Promise<void> => {
        if (!batch) return;
        // A batch can't be manufactured after it was delivered. Catch it here for
        // instant feedback; the server enforces the same rule authoritatively.
        const deliveryDate = batch.delivered_to_patient_date?.split('T')[0];
        if (deliveryDate && dateStr > deliveryDate) {
            toast.error('Manufacture date cannot be later than the delivery date');
            return;
        }
        setSavingDate(true);
        try {
            // Route returns { success, message, data } — fetchJSON unwraps to `data`, so the
            // envelope message isn't available; the static success text covers it.
            await patchJSON(`/api/aligner/batches/${batch.aligner_batch_id}/manufacture`, { targetDate: dateStr });
            toast.success('Manufacture date updated');
            setEditingManufactureDate(false);
            setTempManufactureDate('');
            await onSave(); // Refresh data
        } catch (error) {
            toast.error(httpErrorMessage(error, 'Failed to update manufacture date'));
        } finally {
            setSavingDate(false);
        }
    };

    const handleSetDeliveryDate = async (dateStr: string): Promise<void> => {
        if (!batch) return;
        // Delivery can't predate manufacture. Catch it here for instant feedback;
        // the server enforces the same rule authoritatively.
        const manufactureDate = batch.manufacture_date?.split('T')[0];
        if (manufactureDate && dateStr < manufactureDate) {
            toast.error('Delivery date cannot be earlier than the manufacture date');
            return;
        }
        setSavingDate(true);
        try {
            // Route returns { success, message, data } — fetchJSON unwraps to `data`, so the
            // envelope message isn't available; the static success text covers it.
            await patchJSON(`/api/aligner/batches/${batch.aligner_batch_id}/deliver`, { targetDate: dateStr });
            toast.success('Delivery date updated');
            setEditingDeliveryDate(false);
            setTempDeliveryDate('');
            await onSave(); // Refresh data
        } catch (error) {
            toast.error(httpErrorMessage(error, 'Failed to update delivery date'));
        } finally {
            setSavingDate(false);
        }
    };

    // Block dismissal (backdrop / X / Cancel) while a save or date-apply is in
    // flight so the batch edit can't be abandoned mid-request.
    const handleClose = () => {
        if (!saving && !savingDate) onClose();
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={handleClose}
            overlayClassName="drawer-overlay"
            contentClassName="drawer-container"
        >
            <div className="drawer-header">
                <h2>{batch ? 'Edit Batch' : 'Add New Batch'}</h2>
                <button className="close-btn" onClick={handleClose}>
                    <i className="fas fa-times"></i>
                </button>
            </div>

            <div className="drawer-body">
                <form onSubmit={handleSubmit} className="drawer-form-flex">
                    {/* Action Buttons - Top */}
                    <div className="drawer-footer drawer-footer-top">
                        <button type="button" className="btn btn-secondary" onClick={handleClose} disabled={saving}>
                            Cancel
                        </button>
                        <button type="submit" className="btn btn-primary" disabled={saving}>
                            {saving ? (
                                <>
                                    <i className="fas fa-spinner fa-spin"></i> Saving...
                                </>
                            ) : (
                                <>
                                    <i className="fas fa-save"></i> {batch ? 'Update Batch' : 'Create Batch'}
                                </>
                            )}
                        </button>
                    </div>

                    {/* Basic Info Section - Full Width */}
                    <div className="form-section form-section-compact">
                        <h3 className="section-heading-tight">Basic Information</h3>
                        <div className="form-field">
                            <label htmlFor="BatchSequence">
                                Batch Sequence <span className="required">*</span>
                            </label>
                            <input
                                type="number"
                                id="BatchSequence"
                                name="batch_sequence"
                                value={formData.batch_sequence}
                                onChange={handleChange}
                                className={errors.batch_sequence ? 'error' : ''}
                                min="1"
                            />
                            {errors.batch_sequence && (
                                <span className="error-message">{errors.batch_sequence}</span>
                            )}
                        </div>

                    </div>

                    {/* Two-Column Layout Container - Upper and Lower Aligners */}
                    <div className="form-two-column-container">
                        {/* Left Column - Upper Aligners */}
                        <div className="form-column">
                            <div className="form-section form-section-compact-top">
                                <h3 className="section-heading-no-top">Upper Aligners
                                    {set && (
                                        <span className="remaining-count">
                                            (Remaining: <strong className={(set.remaining_upper_aligners || 0) > 0 ? 'positive' : 'negative'}>{set.remaining_upper_aligners}</strong>)
                                        </span>
                                    )}
                                </h3>

                                {canChangeTemplateOption && (
                                    <div className="form-field-checkbox form-field-checkbox-compact">
                                        <input
                                            type="checkbox"
                                            id="HasUpperTemplate"
                                            checked={hasUpperTemplate}
                                            onChange={(e: ChangeEvent<HTMLInputElement>) => setHasUpperTemplate(e.target.checked)}
                                        />
                                        <label htmlFor="HasUpperTemplate">
                                            Include Template (Start from 0)
                                        </label>
                                    </div>
                                )}

                                <div className="form-field">
                                    <label htmlFor="UpperAlignerStartSequence">Start Sequence (Auto)</label>
                                    <input
                                        type="number"
                                        id="UpperAlignerStartSequence"
                                        value={computedFields.upper_aligner_start_sequence}
                                        readOnly
                                        className="readonly"
                                    />
                                </div>

                                <div className="form-field">
                                    <label htmlFor="UpperAlignerCount">Count</label>
                                    <input
                                        type="number"
                                        id="UpperAlignerCount"
                                        name="upper_aligner_count"
                                        value={formData.upper_aligner_count}
                                        onChange={handleChange}
                                        className={errors.upper_aligner_count ? 'error' : ''}
                                        min="0"
                                        placeholder="Number of aligners"
                                    />
                                    {errors.upper_aligner_count && (
                                        <span className="error-message">{errors.upper_aligner_count}</span>
                                    )}
                                </div>

                                <div className="form-field">
                                    <label htmlFor="UpperAlignerEndSequence">End Sequence (Auto)</label>
                                    <input
                                        type="number"
                                        id="UpperAlignerEndSequence"
                                        value={computedFields.upper_aligner_end_sequence || ''}
                                        readOnly
                                        className="readonly"
                                        placeholder="Auto-calculated"
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Right Column - Lower Aligners */}
                        <div className="form-column">
                            <div className="form-section form-section-compact-top">
                                <h3 className="section-heading-no-top">Lower Aligners
                                    {set && (
                                        <span className="remaining-count">
                                            (Remaining: <strong className={(set.remaining_lower_aligners || 0) > 0 ? 'positive' : 'negative'}>{set.remaining_lower_aligners}</strong>)
                                        </span>
                                    )}
                                </h3>

                                {canChangeTemplateOption && (
                                    <div className="form-field-checkbox form-field-checkbox-compact">
                                        <input
                                            type="checkbox"
                                            id="HasLowerTemplate"
                                            checked={hasLowerTemplate}
                                            onChange={(e: ChangeEvent<HTMLInputElement>) => setHasLowerTemplate(e.target.checked)}
                                        />
                                        <label htmlFor="HasLowerTemplate">
                                            Include Template (Start from 0)
                                        </label>
                                    </div>
                                )}

                                <div className="form-field">
                                    <label htmlFor="LowerAlignerStartSequence">Start Sequence (Auto)</label>
                                    <input
                                        type="number"
                                        id="LowerAlignerStartSequence"
                                        value={computedFields.lower_aligner_start_sequence}
                                        readOnly
                                        className="readonly"
                                    />
                                </div>

                                <div className="form-field">
                                    <label htmlFor="LowerAlignerCount">Count</label>
                                    <input
                                        type="number"
                                        id="LowerAlignerCount"
                                        name="lower_aligner_count"
                                        value={formData.lower_aligner_count}
                                        onChange={handleChange}
                                        className={errors.lower_aligner_count ? 'error' : ''}
                                        min="0"
                                        placeholder="Number of aligners"
                                    />
                                    {errors.lower_aligner_count && (
                                        <span className="error-message">{errors.lower_aligner_count}</span>
                                    )}
                                </div>

                                <div className="form-field">
                                    <label htmlFor="LowerAlignerEndSequence">End Sequence (Auto)</label>
                                    <input
                                        type="number"
                                        id="LowerAlignerEndSequence"
                                        value={computedFields.lower_aligner_end_sequence || ''}
                                        readOnly
                                        className="readonly"
                                        placeholder="Auto-calculated"
                                    />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Dates Section - Full Width */}
                    <div className="form-section form-section-dates">
                        <h3 className="section-heading-no-top">Dates & Timing</h3>


                        {/* Show CreationDate when editing (read-only) */}
                        {batch && batch.creation_date && (
                            <div className="form-row">
                                <div className="form-field">
                                    <label htmlFor="batch-created-on">Created On</label>
                                    <input
                                        id="batch-created-on"
                                        type="text"
                                        value={new Date(batch.creation_date).toLocaleDateString('en-GB', {
                                            year: 'numeric', month: 'short', day: 'numeric',
                                            hour: '2-digit', minute: '2-digit'
                                        })}
                                        readOnly
                                        className="readonly"
                                    />
                                </div>
                            </div>
                        )}

                        <div className="form-row form-row-three-col">
                            {/* Manufacture Date - Read-only with edit */}
                            <div className="form-field">
                                <label htmlFor="batch-manufacture-date">
                                    Manufacture Date
                                    <span className="field-optional-text">(when manufacturing completed)</span>
                                </label>
                                {batch ? (
                                    editingManufactureDate ? (
                                        <div className="date-edit-inline">
                                            <input
                                                id="batch-manufacture-date"
                                                type="date"
                                                value={tempManufactureDate}
                                                onChange={(e: ChangeEvent<HTMLInputElement>) => setTempManufactureDate(e.target.value)}
                                                // Can't be manufactured after it was delivered
                                                max={batch.delivered_to_patient_date?.split('T')[0] || undefined}
                                                // eslint-disable-next-line jsx-a11y/no-autofocus -- intentional focus on open
                                                autoFocus
                                            />
                                            <button
                                                type="button"
                                                className="btn btn-sm btn-primary"
                                                onClick={() => handleSetManufactureDate(tempManufactureDate)}
                                                disabled={!tempManufactureDate || savingDate}
                                            >
                                                {savingDate ? <i className="fas fa-spinner fa-spin"></i> : 'Apply'}
                                            </button>
                                            <button
                                                type="button"
                                                className="btn btn-sm btn-secondary"
                                                onClick={() => { setEditingManufactureDate(false); setTempManufactureDate(''); }}
                                                disabled={savingDate}
                                            >
                                                Cancel
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="date-display-with-actions">
                                            <input
                                                id="batch-manufacture-date"
                                                type="text"
                                                value={formatDisplayDate(batch.manufacture_date)}
                                                readOnly
                                                className="readonly"
                                            />
                                            <button
                                                type="button"
                                                className="btn btn-sm btn-outline"
                                                onClick={() => {
                                                    setTempManufactureDate(batch.manufacture_date?.split('T')[0] || getTodayDateString());
                                                    setEditingManufactureDate(true);
                                                }}
                                                title={batch.manufacture_date ? 'Change date' : 'Set manufacture date'}
                                            >
                                                <i className="fas fa-calendar-alt"></i> {batch.manufacture_date ? 'Edit' : 'Set'}
                                            </button>
                                            {batch.manufacture_date && !batch.delivered_to_patient_date && onUndoManufacture && (
                                                <button
                                                    type="button"
                                                    className="btn btn-sm btn-outline btn-danger"
                                                    onClick={(e: MouseEvent<HTMLButtonElement>) => {
                                                        onUndoManufacture(batch, e);
                                                        onClose();
                                                    }}
                                                    title="Clear manufacture date"
                                                >
                                                    <i className="fas fa-times"></i> Clear
                                                </button>
                                            )}
                                        </div>
                                    )
                                ) : (
                                    <input
                                        id="batch-manufacture-date"
                                        type="text"
                                        value="Set after creating batch"
                                        readOnly
                                        className="readonly"
                                    />
                                )}
                            </div>

                            {/* Delivery Date - Read-only with edit */}
                            <div className="form-field">
                                <label htmlFor="batch-delivered-date">
                                    Delivered Date
                                    <span className="field-optional-text">(when given to patient)</span>
                                </label>
                                {batch ? (
                                    editingDeliveryDate ? (
                                        <div className="date-edit-inline">
                                            <input
                                                id="batch-delivered-date"
                                                type="date"
                                                value={tempDeliveryDate}
                                                onChange={(e: ChangeEvent<HTMLInputElement>) => setTempDeliveryDate(e.target.value)}
                                                // Can't be delivered before it was manufactured
                                                min={batch.manufacture_date?.split('T')[0] || undefined}
                                                // eslint-disable-next-line jsx-a11y/no-autofocus -- intentional focus on open
                                                autoFocus
                                            />
                                            <button
                                                type="button"
                                                className="btn btn-sm btn-primary"
                                                onClick={() => handleSetDeliveryDate(tempDeliveryDate)}
                                                disabled={!tempDeliveryDate || savingDate}
                                            >
                                                {savingDate ? <i className="fas fa-spinner fa-spin"></i> : 'Apply'}
                                            </button>
                                            <button
                                                type="button"
                                                className="btn btn-sm btn-secondary"
                                                onClick={() => { setEditingDeliveryDate(false); setTempDeliveryDate(''); }}
                                                disabled={savingDate}
                                            >
                                                Cancel
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="date-display-with-actions">
                                            <input
                                                id="batch-delivered-date"
                                                type="text"
                                                value={formatDisplayDate(batch.delivered_to_patient_date)}
                                                readOnly
                                                className="readonly"
                                            />
                                            {batch.manufacture_date ? (
                                                <button
                                                    type="button"
                                                    className="btn btn-sm btn-outline"
                                                    onClick={() => {
                                                        setTempDeliveryDate(batch.delivered_to_patient_date?.split('T')[0] || getTodayDateString());
                                                        setEditingDeliveryDate(true);
                                                    }}
                                                    title={batch.delivered_to_patient_date ? 'Change date' : 'Set delivery date'}
                                                >
                                                    <i className="fas fa-calendar-alt"></i> {batch.delivered_to_patient_date ? 'Edit' : 'Set'}
                                                </button>
                                            ) : (
                                                <span className="field-hint">Requires manufacture date</span>
                                            )}
                                            {batch.delivered_to_patient_date && onUndoDelivery && (
                                                <button
                                                    type="button"
                                                    className="btn btn-sm btn-outline btn-danger"
                                                    onClick={(e: MouseEvent<HTMLButtonElement>) => {
                                                        onUndoDelivery(batch, e);
                                                        onClose();
                                                    }}
                                                    title="Clear delivery date"
                                                >
                                                    <i className="fas fa-times"></i> Clear
                                                </button>
                                            )}
                                        </div>
                                    )
                                ) : (
                                    <input
                                        id="batch-delivered-date"
                                        type="text"
                                        value="Set after creating batch"
                                        readOnly
                                        className="readonly"
                                    />
                                )}
                            </div>

                            <div className="form-field">
                                <label htmlFor="Days">Days per Aligner</label>
                                <input
                                    type="number"
                                    id="Days"
                                    name="days"
                                    value={formData.days}
                                    onChange={handleChange}
                                    min="1"
                                    placeholder="Days to wear each aligner"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Notes Section - Full Width */}
                    <div className="form-section form-section-dates">
                        <div className="form-field">
                            <label htmlFor="Notes">Notes</label>
                            <textarea
                                id="Notes"
                                name="notes"
                                value={formData.notes}
                                onChange={handleChange}
                                rows={3}
                                placeholder="Additional notes..."
                            />
                        </div>

                        <div className="form-field-checkbox">
                            <input
                                type="checkbox"
                                id="IsActive"
                                name="is_active"
                                checked={formData.is_active}
                                onChange={handleChange}
                            />
                            <label htmlFor="IsActive">Active (Being used by patient)</label>
                            {errors.is_active && (
                                <span className="error-message">{errors.is_active}</span>
                            )}
                        </div>

                        <div className="form-field-checkbox">
                            <input
                                type="checkbox"
                                id="IsLast"
                                name="is_last"
                                checked={formData.is_last}
                                onChange={handleChange}
                            />
                            <label htmlFor="IsLast">
                                Last Batch (Final batch before new scan or treatment completion)
                            </label>
                            {errors.is_last && (
                                <span className="error-message">{errors.is_last}</span>
                            )}
                        </div>
                    </div>

                    <div className="drawer-footer">
                        <button type="button" className="btn btn-secondary" onClick={handleClose} disabled={saving}>
                            Cancel
                        </button>
                        <button type="submit" className="btn btn-primary" disabled={saving}>
                            {saving ? (
                                <>
                                    <i className="fas fa-spinner fa-spin"></i> Saving...
                                </>
                            ) : (
                                <>
                                    <i className="fas fa-save"></i> {batch ? 'Update Batch' : 'Create Batch'}
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
            </div>
        </div>
    );
};

export default BatchFormDrawer;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { fetchJSON, postJSON, putJSON, deleteJSON, httpErrorMessage } from '@/core/http';
import * as settings from '@shared/contracts/settings.contract';
import * as lookupAdminContract from '@shared/contracts/lookup-admin.contract';
import * as calendarContract from '@shared/contracts/calendar.contract';
import styles from './CalendarTimesSettings.module.css';
import sectionStyles from './SettingsSection.module.css';

interface CalendarTimesSettingsProps {
    onChangesUpdate?: (hasChanges: boolean) => void;
}

interface TimeSlot {
    time_id: number;
    my_time: string;
}

type SlotCategory = 'early' | 'main' | 'late';

interface CategorizedSlots {
    early: string[];
    main: string[];
    late: string[];
}

// GET /api/options/:name success shape ({ status:'success', optionName, value }).
interface OptionResponse {
    value?: string | null;
}

// Helper to parse time from database format (1970-01-01T14:00:00 or HH:MM)
const parseTimeToHHMM = (timeStr: string): string => {
    if (timeStr.includes('T')) {
        // Format: 1970-01-01T14:00:00
        const timePart = timeStr.split('T')[1];
        return timePart.substring(0, 5); // Get HH:MM
    }
    // Already in HH:MM format
    return timeStr.substring(0, 5);
};

// Helper to sort times
const sortTimes = (times: string[]): string[] => {
    return [...times].sort((a, b) => {
        const [aHour, aMin] = a.split(':').map(Number);
        const [bHour, bMin] = b.split(':').map(Number);
        return aHour * 60 + aMin - (bHour * 60 + bMin);
    });
};

const CalendarTimesSettings = ({ onChangesUpdate }: CalendarTimesSettingsProps) => {
    // Time slots from database
    const [allTimeSlots, setAllTimeSlots] = useState<TimeSlot[]>([]);

    // Current category assignments
    const [earlySlots, setEarlySlots] = useState<string[]>([]);
    const [lateSlots, setLateSlots] = useState<string[]>([]);

    // Original values for change detection
    const [originalEarlySlots, setOriginalEarlySlots] = useState<string[]>([]);
    const [originalLateSlots, setOriginalLateSlots] = useState<string[]>([]);

    // Toggle default setting
    const [showExtendedSlotsDefault, setShowExtendedSlotsDefault] = useState(false);
    const [originalShowExtendedDefault, setOriginalShowExtendedDefault] = useState(false);

    // UI state
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isRegenerating, setIsRegenerating] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    // New time slot input
    const [newTimeHour, setNewTimeHour] = useState('');
    const [newTimeMinute, setNewTimeMinute] = useState('00');
    const [newTimeCategory, setNewTimeCategory] = useState<SlotCategory>('main');

    // Delete confirmation
    const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);

    // Get all time strings from database
    const allTimes = useMemo(() => {
        return allTimeSlots.map(slot => parseTimeToHHMM(slot.my_time));
    }, [allTimeSlots]);

    // Categorized slots
    const categorizedSlots = useMemo((): CategorizedSlots => {
        const mainSlots = allTimes.filter(time =>
            !earlySlots.includes(time) && !lateSlots.includes(time)
        );
        return {
            early: sortTimes(earlySlots),
            main: sortTimes(mainSlots),
            late: sortTimes(lateSlots)
        };
    }, [allTimes, earlySlots, lateSlots]);

    // Load all settings
    const loadSettings = useCallback(async () => {
        setIsLoading(true);
        setError(null);

        try {
            // Fetch time slots from database
            const timesData = await fetchJSON<TimeSlot[]>('/api/admin/lookups/tbltimes', { schema: lookupAdminContract.items.response });
            setAllTimeSlots(timesData);

            // /api/options/:name 404s when an option is unset; each GET is tolerant
            // (.catch → null) so a missing one falls back to its default without
            // failing the whole settings load. The rows are seeded today (verified —
            // audit N12/N20), so the 404 path is defensive, not the norm.
            // Fetch early slots option
            const earlyData = await fetchJSON<OptionResponse>('/api/options/CALENDAR_EARLY_SLOTS', { schema: settings.getOptionByName.response }).catch(() => null);
            const earlySlotsArr = earlyData?.value
                ? earlyData.value.split(',').filter(Boolean)
                : ['12:00', '12:30', '13:00', '13:30']; // Default
            setEarlySlots(earlySlotsArr);
            setOriginalEarlySlots(earlySlotsArr);

            // Fetch late slots option
            const lateData = await fetchJSON<OptionResponse>('/api/options/CALENDAR_LATE_SLOTS', { schema: settings.getOptionByName.response }).catch(() => null);
            const lateSlotsArr = lateData?.value
                ? lateData.value.split(',').filter(Boolean)
                : ['21:00', '21:30', '22:00', '22:30']; // Default
            setLateSlots(lateSlotsArr);
            setOriginalLateSlots(lateSlotsArr);

            // Fetch default toggle setting
            const toggleData = await fetchJSON<OptionResponse>('/api/options/CALENDAR_SHOW_EXTENDED_SLOTS_DEFAULT', { schema: settings.getOptionByName.response }).catch(() => null);
            const toggleValue = toggleData?.value === 'true';
            setShowExtendedSlotsDefault(toggleValue);
            setOriginalShowExtendedDefault(toggleValue);

        } catch (err) {
            console.error('Error loading calendar times settings:', err);
            setError('Failed to load settings. Please try again.');
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        loadSettings();
    }, [loadSettings]);

    // Check for changes
    const hasChanges = useMemo(() => {
        const earlyChanged = JSON.stringify(sortTimes(earlySlots)) !== JSON.stringify(sortTimes(originalEarlySlots));
        const lateChanged = JSON.stringify(sortTimes(lateSlots)) !== JSON.stringify(sortTimes(originalLateSlots));
        const toggleChanged = showExtendedSlotsDefault !== originalShowExtendedDefault;
        return earlyChanged || lateChanged || toggleChanged;
    }, [earlySlots, lateSlots, showExtendedSlotsDefault, originalEarlySlots, originalLateSlots, originalShowExtendedDefault]);

    useEffect(() => {
        if (onChangesUpdate) {
            onChangesUpdate(hasChanges);
        }
    }, [hasChanges, onChangesUpdate]);

    // Move slot to a different category
    const moveSlot = (time: string, toCategory: SlotCategory) => {
        // Remove from current category
        setEarlySlots(prev => prev.filter(t => t !== time));
        setLateSlots(prev => prev.filter(t => t !== time));

        // Add to new category (if not main)
        if (toCategory === 'early') {
            setEarlySlots(prev => [...prev, time]);
        } else if (toCategory === 'late') {
            setLateSlots(prev => [...prev, time]);
        }
        // 'main' means not in early or late, so just removing is enough

        setSuccessMessage(null);
    };

    // Add new time slot
    const handleAddTimeSlot = async () => {
        if (!newTimeHour) {
            setError('Please enter an hour');
            return;
        }

        const hour = parseInt(newTimeHour, 10);
        const minute = parseInt(newTimeMinute, 10);

        if (isNaN(hour) || hour < 0 || hour > 23) {
            setError('Hour must be between 0 and 23');
            return;
        }

        const timeStr = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;

        // Check if time already exists
        if (allTimes.includes(timeStr)) {
            setError(`Time slot ${timeStr} already exists`);
            return;
        }

        setError(null);
        setIsSaving(true);

        try {
            // Create the time slot in database
            // Format as 1970-01-01THH:MM:00 to match existing format
            await postJSON('/api/admin/lookups/tbltimes', { my_time: `1970-01-01T${timeStr}:00` });

            // Add to appropriate category
            if (newTimeCategory === 'early') {
                setEarlySlots(prev => [...prev, timeStr]);
            } else if (newTimeCategory === 'late') {
                setLateSlots(prev => [...prev, timeStr]);
            }

            // Reload time slots
            await loadSettings();

            // Clear inputs
            setNewTimeHour('');
            setNewTimeMinute('00');
            setSuccessMessage(`Added time slot ${timeStr}`);
            setTimeout(() => setSuccessMessage(null), 3000);

        } catch (err) {
            console.error('Error adding time slot:', err);
            setError('Failed to add time slot');
        } finally {
            setIsSaving(false);
        }
    };

    // Delete time slot
    const handleDeleteTimeSlot = async (timeStr: string) => {
        const slot = allTimeSlots.find(s => parseTimeToHHMM(s.my_time) === timeStr);
        if (!slot) {
            setError('Time slot not found');
            return;
        }

        setIsSaving(true);
        setError(null);

        try {
            await deleteJSON(`/api/admin/lookups/tbltimes/${slot.time_id}`);

            // Remove from categories
            setEarlySlots(prev => prev.filter(t => t !== timeStr));
            setLateSlots(prev => prev.filter(t => t !== timeStr));

            // Reload time slots
            await loadSettings();

            setDeleteConfirm(null);
            setSuccessMessage(`Deleted time slot ${timeStr}`);
            setTimeout(() => setSuccessMessage(null), 3000);

        } catch (err) {
            console.error('Error deleting time slot:', err);
            setError('Failed to delete time slot');
        } finally {
            setIsSaving(false);
        }
    };

    // Save category assignments
    const handleSave = async () => {
        setIsSaving(true);
        setError(null);
        setSuccessMessage(null);

        try {
            // PUT /api/options/:name is update-only (404s if the row is missing).
            // These three are seeded (verified — audit N12/N20), so a non-2xx is a
            // genuine failure that putJSON now throws → the catch surfaces it,
            // instead of the old fire-and-forget that always reported success.
            await putJSON('/api/options/CALENDAR_EARLY_SLOTS', { value: sortTimes(earlySlots).join(',') });
            await putJSON('/api/options/CALENDAR_LATE_SLOTS', { value: sortTimes(lateSlots).join(',') });
            await putJSON('/api/options/CALENDAR_SHOW_EXTENDED_SLOTS_DEFAULT', { value: showExtendedSlotsDefault.toString() });

            // Update original values
            setOriginalEarlySlots([...earlySlots]);
            setOriginalLateSlots([...lateSlots]);
            setOriginalShowExtendedDefault(showExtendedSlotsDefault);

            setSuccessMessage('Settings saved successfully!');
            setTimeout(() => setSuccessMessage(null), 3000);

        } catch (err) {
            console.error('Error saving settings:', err);
            setError('Failed to save settings. Please try again.');
        } finally {
            setIsSaving(false);
        }
    };

    // Reset changes
    const handleReset = () => {
        setEarlySlots([...originalEarlySlots]);
        setLateSlots([...originalLateSlots]);
        setShowExtendedSlotsDefault(originalShowExtendedDefault);
        setSuccessMessage(null);
        setError(null);
    };

    // Regenerate calendar entries
    const handleRegenerateCalendar = async () => {
        setIsRegenerating(true);
        setError(null);
        setSuccessMessage(null);

        try {
            const data = await postJSON<{ entriesAdded?: number; message?: string }>(
                '/api/calendar/regenerate',
                {},
                { schema: calendarContract.regenerate.response }
            );

            setSuccessMessage(data.message || `Added ${data.entriesAdded} calendar entries`);
            setTimeout(() => setSuccessMessage(null), 5000);
        } catch (err) {
            console.error('Error regenerating calendar:', err);
            setError(httpErrorMessage(err, 'Failed to regenerate calendar'));
        } finally {
            setIsRegenerating(false);
        }
    };

    // Render a time slot chip with move buttons
    // Movement rules:
    // - Early: can move to Main only (not to Late)
    // - Late: can move to Main only (not to Early)
    // - Main: can move to both Early and Late
    const renderTimeChip = (time: string, category: SlotCategory) => {
        const isDeleting = deleteConfirm === time;

        // Determine which move buttons to show based on category
        const canMoveToEarly = category === 'main'; // Only main can move to early
        const canMoveToMain = category !== 'main';  // Early and late can move to main
        const canMoveToLate = category === 'main';  // Only main can move to late

        return (
            <div key={time} className={styles.timeChipWrapper}>
                <span className={styles.timeChip}>{time}</span>
                <div className={styles.chipActions}>
                    {canMoveToEarly && (
                        <button
                            className={styles.moveBtn}
                            onClick={() => moveSlot(time, 'early')}
                            title="Move to Early"
                            disabled={isSaving}
                        >
                            <i className="fas fa-sun"></i>
                        </button>
                    )}
                    {canMoveToMain && (
                        <button
                            className={styles.moveBtn}
                            onClick={() => moveSlot(time, 'main')}
                            title="Move to Main"
                            disabled={isSaving}
                        >
                            <i className="fas fa-calendar"></i>
                        </button>
                    )}
                    {canMoveToLate && (
                        <button
                            className={styles.moveBtn}
                            onClick={() => moveSlot(time, 'late')}
                            title="Move to Late"
                            disabled={isSaving}
                        >
                            <i className="fas fa-moon"></i>
                        </button>
                    )}
                    {isDeleting ? (
                        <>
                            <button
                                className={`${styles.moveBtn} ${styles.confirmDelete}`}
                                onClick={() => handleDeleteTimeSlot(time)}
                                title="Confirm Delete"
                                disabled={isSaving}
                            >
                                <i className="fas fa-check"></i>
                            </button>
                            <button
                                className={styles.moveBtn}
                                onClick={() => setDeleteConfirm(null)}
                                title="Cancel"
                                disabled={isSaving}
                            >
                                <i className="fas fa-times"></i>
                            </button>
                        </>
                    ) : (
                        <button
                            className={`${styles.moveBtn} ${styles.deleteBtn}`}
                            onClick={() => setDeleteConfirm(time)}
                            title="Delete"
                            disabled={isSaving}
                        >
                            <i className="fas fa-trash"></i>
                        </button>
                    )}
                </div>
            </div>
        );
    };

    if (isLoading) {
        return (
            <div className={sectionStyles.section}>
                <div className={sectionStyles.loadingContainer}>
                    <i className="fas fa-spinner fa-spin"></i>
                    <span>Loading calendar time settings...</span>
                </div>
            </div>
        );
    }

    return (
        <div>
            <div className={sectionStyles.section}>
                <h3>
                    <i className="fas fa-clock"></i>
                    Calendar Time Slots
                </h3>
                <p className={sectionStyles.sectionDescription}>
                    Manage time slots and their categories. Early and Late slots can be toggled on/off in the calendar.
                </p>

                {error && (
                    <div className={styles.errorMessage}>
                        <i className="fas fa-exclamation-circle"></i>
                        {error}
                    </div>
                )}

                {successMessage && (
                    <div className={styles.successMessage}>
                        <i className="fas fa-check-circle"></i>
                        {successMessage}
                    </div>
                )}

                <div className={styles.settingsContent}>
                    {/* Toggle Setting */}
                    <div className={styles.toggleSection}>
                        <div className={styles.toggleRow}>
                            <div className={styles.toggleInfo}>
                                <label htmlFor="showExtendedSlots" className={styles.toggleLabel}>
                                    Show early & late slots by default
                                </label>
                                <p className={styles.toggleDescription}>
                                    When enabled, early and late time slots are visible by default in the calendar.
                                </p>
                            </div>
                            <label className={styles.switch} htmlFor="showExtendedSlots" aria-label="Show early & late slots by default">
                                <input
                                    type="checkbox"
                                    id="showExtendedSlots"
                                    checked={showExtendedSlotsDefault}
                                    onChange={() => setShowExtendedSlotsDefault(prev => !prev)}
                                />
                                <span className={styles.slider}></span>
                            </label>
                        </div>
                    </div>

                    {/* Add New Time Slot */}
                    <div className={styles.addSlotSection}>
                        <h4>
                            <i className="fas fa-plus-circle"></i>
                            Add New Time Slot
                        </h4>
                        <div className={styles.addSlotForm}>
                            <div className={styles.timeInputGroup}>
                                <input
                                    type="number"
                                    min="0"
                                    max="23"
                                    placeholder="HH"
                                    value={newTimeHour}
                                    onChange={(e) => setNewTimeHour(e.target.value)}
                                    className={styles.timeInput}
                                />
                                <span className={styles.timeSeparator}>:</span>
                                <select
                                    value={newTimeMinute}
                                    onChange={(e) => setNewTimeMinute(e.target.value)}
                                    className={styles.minuteSelect}
                                >
                                    <option value="00">00</option>
                                    <option value="30">30</option>
                                </select>
                            </div>
                            <select
                                value={newTimeCategory}
                                onChange={(e) => setNewTimeCategory(e.target.value as SlotCategory)}
                                className={styles.categorySelect}
                            >
                                <option value="early">Early</option>
                                <option value="main">Main</option>
                                <option value="late">Late</option>
                            </select>
                            <button
                                className="btn btn-primary"
                                onClick={handleAddTimeSlot}
                                disabled={isSaving || !newTimeHour}
                            >
                                <i className="fas fa-plus"></i>
                                Add
                            </button>
                        </div>
                    </div>

                    {/* Time Slot Categories */}
                    <div className={styles.categoriesSection}>
                        {/* Early Slots */}
                        <div className={`${styles.slotCategory} ${styles.earlyCategory}`}>
                            <div className={styles.categoryHeader}>
                                <i className="fas fa-sun"></i>
                                <span>Early Slots</span>
                                <span className={styles.categoryCount}>{categorizedSlots.early.length}</span>
                            </div>
                            <p className={styles.categoryNote}>
                                Hidden by default (e.g., lunch hours)
                            </p>
                            <div className={styles.slotTimes}>
                                {categorizedSlots.early.length === 0 ? (
                                    <span className={styles.emptyCategory}>No early slots</span>
                                ) : (
                                    categorizedSlots.early.map(time => renderTimeChip(time, 'early'))
                                )}
                            </div>
                        </div>

                        {/* Main Slots */}
                        <div className={`${styles.slotCategory} ${styles.mainCategory}`}>
                            <div className={styles.categoryHeader}>
                                <i className="fas fa-calendar"></i>
                                <span>Main Slots</span>
                                <span className={styles.categoryCount}>{categorizedSlots.main.length}</span>
                            </div>
                            <p className={styles.categoryNote}>
                                Always visible in the calendar
                            </p>
                            <div className={styles.slotTimes}>
                                {categorizedSlots.main.length === 0 ? (
                                    <span className={styles.emptyCategory}>No main slots</span>
                                ) : (
                                    categorizedSlots.main.map(time => renderTimeChip(time, 'main'))
                                )}
                            </div>
                        </div>

                        {/* Late Slots */}
                        <div className={`${styles.slotCategory} ${styles.lateCategory}`}>
                            <div className={styles.categoryHeader}>
                                <i className="fas fa-moon"></i>
                                <span>Late Slots</span>
                                <span className={styles.categoryCount}>{categorizedSlots.late.length}</span>
                            </div>
                            <p className={styles.categoryNote}>
                                Hidden by default (e.g., Ramadan hours)
                            </p>
                            <div className={styles.slotTimes}>
                                {categorizedSlots.late.length === 0 ? (
                                    <span className={styles.emptyCategory}>No late slots</span>
                                ) : (
                                    categorizedSlots.late.map(time => renderTimeChip(time, 'late'))
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className={sectionStyles.actions}>
                <button
                    className="btn btn-primary"
                    onClick={handleSave}
                    disabled={!hasChanges || isSaving}
                >
                    {isSaving ? (
                        <>
                            <i className="fas fa-spinner fa-spin"></i>
                            Saving...
                        </>
                    ) : (
                        <>
                            <i className="fas fa-save"></i>
                            Save Changes
                        </>
                    )}
                </button>
                <button
                    className="btn btn-secondary"
                    onClick={handleReset}
                    disabled={!hasChanges || isSaving}
                >
                    <i className="fas fa-undo"></i>
                    Reset
                </button>
            </div>

            {/* Regenerate Calendar Section */}
            <div className={`${sectionStyles.section} ${styles.regenerateSection}`}>
                <h3>
                    <i className="fas fa-sync-alt"></i>
                    Regenerate Calendar
                </h3>
                <p className={sectionStyles.sectionDescription}>
                    If you've added new time slots, click this button to populate them into the calendar for all future dates.
                </p>
                <button
                    className={`btn btn-secondary ${styles.regenerateButton}`}
                    onClick={handleRegenerateCalendar}
                    disabled={isRegenerating || isSaving}
                >
                    {isRegenerating ? (
                        <>
                            <i className="fas fa-spinner fa-spin"></i>
                            Regenerating...
                        </>
                    ) : (
                        <>
                            <i className="fas fa-sync-alt"></i>
                            Regenerate Calendar Entries
                        </>
                    )}
                </button>
            </div>
        </div>
    );
};

export default CalendarTimesSettings;

import { useState, useEffect, ChangeEvent, FormEvent } from 'react';
import { useToast } from '../../contexts/ToastContext';
import { useConfirm } from '../../contexts/ConfirmContext';
import { fetchJSON, postJSON, putJSON, deleteJSON, httpErrorMessage } from '@/core/http';
import * as costPreset from '@shared/contracts/cost-preset.contract';
import styles from './CostPresetsSettings.module.css';

type Currency = 'IQD' | 'USD' | 'EUR';

interface CostPreset {
    preset_id: number;
    amount: number;
    currency: Currency;
    display_order: number;
}

interface FormData {
    amount: string;
    currency: Currency;
    displayOrder: number;
}

const CostPresetsSettings = () => {
    const toast = useToast();
    const confirm = useConfirm();
    const [presets, setPresets] = useState<CostPreset[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeCurrency, setActiveCurrency] = useState<Currency>('IQD');
    const [editingPreset, setEditingPreset] = useState<CostPreset | null>(null);
    const [formData, setFormData] = useState<FormData>({
        amount: '',
        currency: 'IQD',
        displayOrder: 0
    });
    const [displayAmount, setDisplayAmount] = useState('');

    // Load presets
    const loadPresets = async () => {
        try {
            setLoading(true);
            const data = await fetchJSON<CostPreset[]>('/api/settings/cost-presets', { schema: costPreset.getPresets.response });
            setPresets(data);
        } catch (error) {
            console.error('Error loading presets:', error);
            toast.error(httpErrorMessage(error, 'Failed to load cost presets'));
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadPresets();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Filter presets by currency
    const filteredPresets = presets.filter(p => p.currency === activeCurrency);

    // Handle form input changes
    const handleInputChange = (e: ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    // Create new preset
    const handleCreatePreset = async (e: FormEvent<HTMLFormElement>) => {
        e.preventDefault();

        if (!formData.amount || parseFloat(formData.amount) <= 0) {
            toast.warning('Please enter a valid amount');
            return;
        }

        try {
            await postJSON('/api/settings/cost-presets', {
                amount: parseFloat(formData.amount),
                currency: formData.currency,
                displayOrder: parseInt(String(formData.displayOrder)) || 0
            });

            toast.success('Preset created successfully');
            setFormData({ amount: '', currency: activeCurrency, displayOrder: 0 });
            setDisplayAmount('');
            loadPresets();
        } catch (error) {
            console.error('Error creating preset:', error);
            toast.error(httpErrorMessage(error, 'Failed to create preset'));
        }
    };

    // Edit preset
    const handleEditPreset = (preset: CostPreset) => {
        setEditingPreset(preset);
        setFormData({
            amount: String(preset.amount),
            currency: preset.currency,
            displayOrder: preset.display_order
        });
        setDisplayAmount(preset.amount ? formatNumber(preset.amount) : '');
    };

    // Update preset
    const handleUpdatePreset = async (e: FormEvent<HTMLFormElement>) => {
        e.preventDefault();

        if (!formData.amount || parseFloat(formData.amount) <= 0) {
            toast.warning('Please enter a valid amount');
            return;
        }

        if (!editingPreset) return;

        try {
            await putJSON(`/api/settings/cost-presets/${editingPreset.preset_id}`, {
                amount: parseFloat(formData.amount),
                currency: formData.currency,
                displayOrder: parseInt(String(formData.displayOrder)) || 0
            });

            toast.success('Preset updated successfully');
            setEditingPreset(null);
            setFormData({ amount: '', currency: activeCurrency, displayOrder: 0 });
            setDisplayAmount('');
            loadPresets();
        } catch (error) {
            console.error('Error updating preset:', error);
            toast.error(httpErrorMessage(error, 'Failed to update preset'));
        }
    };

    // Delete preset
    const handleDeletePreset = async (preset_id: number) => {
        if (!await confirm('Are you sure you want to delete this preset?', { title: 'Delete Preset', danger: true, confirmText: 'Delete' })) {
            return;
        }

        try {
            await deleteJSON(`/api/settings/cost-presets/${preset_id}`);

            toast.success('Preset deleted successfully');
            loadPresets();
        } catch (error) {
            console.error('Error deleting preset:', error);
            toast.error(httpErrorMessage(error, 'Failed to delete preset'));
        }
    };

    // Cancel edit
    const handleCancelEdit = () => {
        setEditingPreset(null);
        setFormData({ amount: '', currency: activeCurrency, displayOrder: 0 });
        setDisplayAmount('');
    };

    // Format number with commas
    const formatNumber = (num: number): string => {
        return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    };

    if (loading) {
        return (
            <div className={`${styles.costPresetsSettings} ${styles.loading}`}>
                <i className="fas fa-spinner fa-spin fa-2x"></i>
                <p>Loading cost presets...</p>
            </div>
        );
    }

    return (
        <div className={styles.costPresetsSettings}>
            {/* Currency Tabs */}
            <div className={styles.currencyTabs}>
                <button
                    className={`${styles.currencyTab} ${activeCurrency === 'IQD' ? styles.active : ''}`}
                    onClick={() => setActiveCurrency('IQD')}
                >
                    <i className="fas fa-coins"></i> IQD
                </button>
                <button
                    className={`${styles.currencyTab} ${activeCurrency === 'USD' ? styles.active : ''}`}
                    onClick={() => setActiveCurrency('USD')}
                >
                    <i className="fas fa-dollar-sign"></i> USD
                </button>
                <button
                    className={`${styles.currencyTab} ${activeCurrency === 'EUR' ? styles.active : ''}`}
                    onClick={() => setActiveCurrency('EUR')}
                >
                    <i className="fas fa-euro-sign"></i> EUR
                </button>
            </div>

            <div className={styles.presetsContent}>
                {/* Add/Edit Form */}
                <div className={styles.presetFormCard}>
                    <h3>{editingPreset ? 'Edit Preset' : 'Add New Preset'}</h3>
                    <form onSubmit={editingPreset ? handleUpdatePreset : handleCreatePreset}>
                        <div className={styles.formGroup}>
                            <label htmlFor="amount">Amount</label>
                            <input
                                type="text"
                                id="amount"
                                name="amount"
                                value={displayAmount}
                                onChange={(e) => {
                                    const digits = e.target.value.replace(/[^\d]/g, '');
                                    const num = parseInt(digits, 10) || 0;
                                    setDisplayAmount(num ? num.toLocaleString('en-US') : '');
                                    setFormData(prev => ({ ...prev, amount: String(num) }));
                                }}
                                onBlur={() => setDisplayAmount(formData.amount ? formatNumber(parseInt(formData.amount, 10)) : '')}
                                placeholder="Enter amount"
                                required
                            />
                        </div>

                        <div className={styles.formGroup}>
                            <label htmlFor="currency">Currency</label>
                            <select
                                id="currency"
                                name="currency"
                                value={formData.currency}
                                onChange={handleInputChange}
                            >
                                <option value="IQD">IQD</option>
                                <option value="USD">USD</option>
                                <option value="EUR">EUR</option>
                            </select>
                        </div>

                        <div className={styles.formGroup}>
                            <label htmlFor="displayOrder">Display Order</label>
                            <input
                                type="number"
                                id="displayOrder"
                                name="displayOrder"
                                value={formData.displayOrder}
                                onChange={handleInputChange}
                                placeholder="0"
                            />
                        </div>

                        <div className={styles.formActions}>
                            {editingPreset ? (
                                <>
                                    <button type="submit" className="btn btn-primary">
                                        <i className="fas fa-save"></i> Update
                                    </button>
                                    <button type="button" className="btn btn-secondary" onClick={handleCancelEdit}>
                                        <i className="fas fa-times"></i> Cancel
                                    </button>
                                </>
                            ) : (
                                <button type="submit" className="btn btn-primary">
                                    <i className="fas fa-plus"></i> Add Preset
                                </button>
                            )}
                        </div>
                    </form>
                </div>

                {/* Presets Table */}
                <div className={styles.presetsTableCard}>
                    <h3>{activeCurrency} Presets ({filteredPresets.length})</h3>
                    {filteredPresets.length > 0 ? (
                        <table className={styles.presetsTable}>
                            <thead>
                                <tr>
                                    <th>Amount</th>
                                    <th>Currency</th>
                                    <th>Display Order</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredPresets.map(preset => (
                                    <tr key={preset.preset_id}>
                                        <td>{formatNumber(preset.amount)}</td>
                                        <td>{preset.currency}</td>
                                        <td>{preset.display_order}</td>
                                        <td className={styles.actions}>
                                            <button
                                                className={`${styles.btnIcon} ${styles.btnEdit}`}
                                                onClick={() => handleEditPreset(preset)}
                                                title="Edit"
                                            >
                                                <i className="fas fa-edit"></i>
                                            </button>
                                            <button
                                                className={`${styles.btnIcon} ${styles.btnDelete}`}
                                                onClick={() => handleDeletePreset(preset.preset_id)}
                                                title="Delete"
                                            >
                                                <i className="fas fa-trash"></i>
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    ) : (
                        <div className={styles.emptyState}>
                            <i className="fas fa-inbox fa-3x"></i>
                            <p>No presets found for {activeCurrency}</p>
                            <p className={styles.hint}>Add a preset using the form above</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default CostPresetsSettings;

