import { useState, useEffect, useCallback, useRef } from 'react';
import { fetchJSON, httpErrorMessage } from '@/core/http';
import styles from './SupabaseStatusSettings.module.css';

/**
 * Read-only Settings tab: live status of the one-way Dolphin CDC sink (sink 'dolphin' → the legacy
 * Dolphin Imaging SQL Server). The mirror of SupabaseStatusSettings — same card shape, same poll
 * cadence, same CSS module — but it targets GET /api/sync/dolphin-status (feed local, ping the mssql
 * server). Never reports unsaved changes, so the tab never shows a Save badge.
 */

const POLL_MS = 10_000;

interface SinkStatus {
    sink: 'dolphin';
    configured: boolean;
    envEnabled: boolean;
    enabled: boolean;
    stale: boolean;
    note: string | null;
    updatedAt: string | null;
    backlog: number;
    reachable: boolean | null;
    latencyMs: number | null;
    error: string | null;
}

interface StatusResponse {
    success: boolean;
    checkedAt?: string;
    sinks?: SinkStatus[];
    error?: string;
}

interface DolphinStatusSettingsProps {
    onChangesUpdate?: (hasChanges: boolean) => void;
}

const SINK_META: Record<SinkStatus['sink'], { label: string; description: string }> = {
    dolphin: {
        label: 'Dolphin Imaging',
        description: 'One-way sink: native timepoints/images → the legacy Dolphin Imaging SQL Server (temporary; slated for removal).',
    },
};

type Health = 'ok' | 'warn' | 'down' | 'off';

function sinkHealth(s: SinkStatus): Health {
    if (!s.configured || !s.enabled) return 'off';
    if (s.reachable === false) return 'down';
    if (s.stale || s.backlog > 0) return 'warn';
    return 'ok';
}

const HEALTH_LABEL: Record<Health, string> = {
    ok: 'Online',
    warn: 'Degraded',
    down: 'Unreachable',
    off: 'Disabled',
};

function formatTime(iso: string | null): string {
    if (!iso) return '—';
    const d = new Date(iso);
    return Number.isNaN(d.getTime()) ? iso : d.toLocaleString();
}

const DolphinStatusSettings = ({ onChangesUpdate }: DolphinStatusSettingsProps) => {
    const [sinks, setSinks] = useState<SinkStatus[] | null>(null);
    const [checkedAt, setCheckedAt] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const isMounted = useRef(true);

    // Read-only tab: explicitly declare no unsaved changes so no Save badge ever shows.
    useEffect(() => {
        onChangesUpdate?.(false);
    }, [onChangesUpdate]);

    const fetchStatus = useCallback(async (): Promise<void> => {
        try {
            // Raw read (no contract): single sync/CDC status endpoint in sync-webhook.ts,
            // outside the staff-app contract surface. Left unguarded by design (mirrors
            // the sibling Supabase status read).
            // eslint-disable-next-line no-restricted-syntax -- raw out-of-surface sync status read
            const data = await fetchJSON<StatusResponse>('/api/sync/dolphin-status');
            if (!isMounted.current) return;
            if (data.success && data.sinks) {
                setSinks(data.sinks);
                setCheckedAt(data.checkedAt ?? new Date().toISOString());
                setError(null);
            } else {
                setError(data.error || 'Failed to load Dolphin status');
            }
        } catch (err) {
            if (isMounted.current) setError(httpErrorMessage(err, 'Failed to load Dolphin status'));
        } finally {
            if (isMounted.current) setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        isMounted.current = true;
        fetchStatus();
        const id = setInterval(fetchStatus, POLL_MS);
        return () => {
            isMounted.current = false;
            clearInterval(id);
        };
    }, [fetchStatus]);

    return (
        <div className={styles.container}>
            <div className={styles.header}>
                <div>
                    <h3 className={styles.title}>
                        <i className="fas fa-database"></i>
                        Dolphin Sync Status
                    </h3>
                    <p className={styles.description}>
                        Live reachability of the legacy Dolphin Imaging SQL Server sink. Refreshes automatically every{' '}
                        {POLL_MS / 1000}s.
                    </p>
                </div>
                <div className={styles.headerActions}>
                    <span className={styles.checkedAt}>Last checked: {formatTime(checkedAt)}</span>
                    <button
                        type="button"
                        className={styles.refreshBtn}
                        onClick={fetchStatus}
                        disabled={isLoading}
                    >
                        <i className={`fas fa-sync-alt ${isLoading ? styles.spin : ''}`}></i>
                        Refresh now
                    </button>
                </div>
            </div>

            {error && (
                <div className={styles.errorBanner}>
                    <i className="fas fa-exclamation-triangle"></i>
                    <span>{error}</span>
                </div>
            )}

            {isLoading && !sinks ? (
                <div className={styles.loading}>
                    <i className="fas fa-spinner fa-spin"></i>
                    <span>Checking Dolphin status…</span>
                </div>
            ) : (
                <div className={styles.cards}>
                    {sinks?.map((s) => {
                        const health = sinkHealth(s);
                        const meta = SINK_META[s.sink];
                        return (
                            <div key={s.sink} className={`${styles.card} ${styles[health]}`}>
                                <div className={styles.cardHeader}>
                                    <span className={styles.sinkName}>{meta.label}</span>
                                    <span className={`${styles.badge} ${styles[health]}`}>
                                        <span className={styles.dot}></span>
                                        {HEALTH_LABEL[health]}
                                    </span>
                                </div>
                                <p className={styles.sinkDescription}>{meta.description}</p>

                                <dl className={styles.rows}>
                                    <div className={styles.row}>
                                        <dt>Configured</dt>
                                        <dd>{s.configured ? 'Yes' : 'No (DB_* vars missing)'}</dd>
                                    </div>
                                    <div className={styles.row}>
                                        <dt>Reachable</dt>
                                        <dd>
                                            {!s.configured
                                                ? '—'
                                                : s.reachable
                                                  ? `Yes${s.latencyMs != null ? ` (${s.latencyMs} ms)` : ''}`
                                                  : `No${s.error ? ` — ${s.error}` : ''}`}
                                        </dd>
                                    </div>
                                    <div className={styles.row}>
                                        <dt>Capture enabled</dt>
                                        <dd>{s.enabled ? 'Yes' : 'No'}</dd>
                                    </div>
                                    <div className={styles.row}>
                                        <dt>Stale (needs reload)</dt>
                                        <dd className={s.stale ? styles.warnText : ''}>{s.stale ? 'Yes' : 'No'}</dd>
                                    </div>
                                    <div className={styles.row}>
                                        <dt>Pending backlog</dt>
                                        <dd className={s.backlog > 0 ? styles.warnText : ''}>
                                            {s.backlog.toLocaleString()} change(s)
                                        </dd>
                                    </div>
                                    <div className={styles.row}>
                                        <dt>Last status</dt>
                                        <dd>
                                            {s.note || '—'}
                                            {s.updatedAt && (
                                                <span className={styles.subtle}> · {formatTime(s.updatedAt)}</span>
                                            )}
                                        </dd>
                                    </div>
                                </dl>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default DolphinStatusSettings;

