import React, { useState, useEffect, useCallback } from 'react';
import AsyncSelect from 'react-select/async';
import type { StylesConfig } from 'react-select';
import cn from 'classnames';
import { formatPhoneForDisplay } from '../../utils/phoneFormatter';
import { fetchJSON, httpErrorMessage } from '@/core/http';
import { patientPhones } from '@shared/contracts/patient.contract';
import styles from './PatientQuickSearch.module.css';

/**
 * Patient data from /api/patients/phones endpoint
 */
export interface PatientOption {
    id: number;
    name?: string;
    phone?: string;
}

/**
 * Select option format for react-select
 */
interface SelectOption {
    value: number;
    label: string;
}

/**
 * Selected patient data returned to parent
 */
export interface SelectedPatient {
    person_id: number;
    patient_name: string;
    phone?: string;
}

/**
 * Props for PatientQuickSearch component
 */
export interface PatientQuickSearchProps {
    /** Callback when a patient is selected */
    onSelect: (patient: SelectedPatient) => void;
    /** Array of patient IDs to exclude from results */
    excludePatientIds?: number[];
    /** Layout orientation */
    layout?: 'horizontal' | 'vertical';
    /** Whether to show the header section */
    showHeader?: boolean;
    /** Whether to auto-focus the first input */
    autoFocus?: boolean;
    /** Pre-loaded patient data (from route loader) */
    allPatients?: PatientOption[];
    /** Custom class name for container */
    className?: string;
}

/**
 * PatientQuickSearch Component
 *
 * Reusable patient search component with 3 search modes:
 * - Name (Arabic/RTL)
 * - Phone
 * - ID
 *
 * Uses client-side filtering for instant results.
 */
const PatientQuickSearch: React.FC<PatientQuickSearchProps> = ({
    onSelect,
    excludePatientIds = [],
    layout = 'horizontal',
    showHeader = true,
    autoFocus = false,
    allPatients: providedPatients,
    className
}) => {
    const [patients, setPatients] = useState<PatientOption[]>(providedPatients || []);
    const [loading, setLoading] = useState(!providedPatients);
    const [error, setError] = useState<string | null>(null);

    // Fetch patients if not provided via props
    useEffect(() => {
        if (providedPatients) {
            setPatients(providedPatients);
            setLoading(false);
            return;
        }

        const fetchPatients = async () => {
            try {
                setLoading(true);
                const data = await fetchJSON<PatientOption[]>('/api/patients/phones', { schema: patientPhones.response });
                setPatients(data);
                setError(null);
            } catch (err) {
                console.error('Failed to fetch patients:', err);
                setError(httpErrorMessage(err, 'Failed to load patients'));
            } finally {
                setLoading(false);
            }
        };

        fetchPatients();
    }, [providedPatients]);

    // Filter out excluded patients
    const filteredPatients = patients.filter(
        p => !excludePatientIds.includes(p.id)
    );

    // Handle selection - convert to SelectedPatient format
    const handleSelect = useCallback((option: SelectOption | null) => {
        if (!option) return;

        const patient = filteredPatients.find(p => p.id === option.value);
        if (patient) {
            onSelect({
                person_id: patient.id,
                patient_name: patient.name || '',
                phone: patient.phone
            });
        }
    }, [filteredPatients, onSelect]);

    // Search by Name (Arabic)
    const loadNameOptions = useCallback((input: string, callback: (options: SelectOption[]) => void) => {
        if (input.length < 2) {
            callback([]);
            return;
        }
        const results = filteredPatients
            .filter(p => p.name?.startsWith(input))
            .slice(0, 50)
            .map(p => ({ value: p.id, label: p.name || '' }));
        callback(results);
    }, [filteredPatients]);

    // Search by Phone
    const loadPhoneOptions = useCallback((input: string, callback: (options: SelectOption[]) => void) => {
        if (input.length < 2) {
            callback([]);
            return;
        }
        const results = filteredPatients
            .filter(p => p.phone?.includes(input))
            .slice(0, 50)
            .map(p => ({ value: p.id, label: formatPhoneForDisplay(p.phone) }));
        callback(results);
    }, [filteredPatients]);

    // Search by ID
    const loadIdOptions = useCallback((input: string, callback: (options: SelectOption[]) => void) => {
        if (input.length < 1) {
            callback([]);
            return;
        }
        const results = filteredPatients
            .filter(p => p.id?.toString().includes(input))
            .slice(0, 50)
            .map(p => ({ value: p.id, label: p.id.toString() }));
        callback(results);
    }, [filteredPatients]);

    // Base styles for all selects - use CSS variable for consistent height
    const selectStylesBase: StylesConfig<SelectOption, false> = {
        control: (provided) => ({
            ...provided,
            minHeight: 'var(--input-height)'
        })
    };

    // RTL styles for Arabic name search
    const selectStylesRTL: StylesConfig<SelectOption, false> = {
        control: (provided) => ({
            ...provided,
            minHeight: 'var(--input-height)'
        }),
        input: (provided) => ({
            ...provided,
            direction: 'rtl' as const,
            textAlign: 'right' as const
        }),
        singleValue: (provided) => ({
            ...provided,
            direction: 'rtl' as const,
            textAlign: 'right' as const
        }),
        placeholder: (provided) => ({
            ...provided,
            direction: 'rtl' as const,
            textAlign: 'right' as const
        })
    };

    // Loading state
    if (loading) {
        return (
            <div className={cn(styles.container, className)}>
                <div className={styles.loadingState}>
                    <i className="fas fa-spinner fa-spin"></i>
                    <span>Loading patients...</span>
                </div>
            </div>
        );
    }

    // Error state
    if (error) {
        return (
            <div className={cn(styles.container, className)}>
                <div className={styles.errorState}>
                    <i className="fas fa-exclamation-circle"></i>
                    <span>{error}</span>
                </div>
            </div>
        );
    }

    return (
        <div className={cn(styles.container, className)}>
            {showHeader && (
                <div className={styles.header}>
                    <i className="fas fa-bolt"></i>
                    <h3>Quick Search - Select & Go</h3>
                </div>
            )}

            <div className={cn(
                styles.searchGrid,
                layout === 'vertical' && styles.searchGridVertical
            )}>
                {/* Search by Name (Arabic) */}
                <div className={styles.searchField}>
                    <label htmlFor="pqs-search-name">
                        <i className={cn('fas fa-user', styles.iconGap)}></i>
                        Search by Name (Arabic)
                    </label>
                    <AsyncSelect<SelectOption, false>
                        inputId="pqs-search-name"
                        cacheOptions
                        defaultOptions={false}
                        loadOptions={loadNameOptions}
                        onChange={handleSelect}
                        placeholder="اكتب للبحث..."
                        isClearable
                        classNamePrefix="pqs-select"
                        styles={selectStylesRTL}
                        // eslint-disable-next-line jsx-a11y/no-autofocus -- intentional focus on open
                        autoFocus={autoFocus}
                        noOptionsMessage={({ inputValue }) =>
                            inputValue.length < 2 ? 'Type at least 2 characters...' : 'No patients found'
                        }
                    />
                </div>

                {/* Search by Phone */}
                <div className={styles.searchField}>
                    <label htmlFor="pqs-search-phone">
                        <i className={cn('fas fa-phone', styles.iconGap)}></i>
                        Search by Phone
                    </label>
                    <AsyncSelect<SelectOption, false>
                        inputId="pqs-search-phone"
                        cacheOptions
                        defaultOptions={false}
                        loadOptions={loadPhoneOptions}
                        onChange={handleSelect}
                        placeholder="Search phone..."
                        isClearable
                        classNamePrefix="pqs-select"
                        styles={selectStylesBase}
                        noOptionsMessage={({ inputValue }) =>
                            inputValue.length < 2 ? 'Type at least 2 characters...' : 'No patients found'
                        }
                    />
                </div>

                {/* Search by ID */}
                <div className={styles.searchField}>
                    <label htmlFor="pqs-search-id">
                        <i className={cn('fas fa-id-card', styles.iconGap)}></i>
                        Search by ID
                    </label>
                    <AsyncSelect<SelectOption, false>
                        inputId="pqs-search-id"
                        cacheOptions
                        defaultOptions={false}
                        loadOptions={loadIdOptions}
                        onChange={handleSelect}
                        placeholder="Search ID..."
                        isClearable
                        classNamePrefix="pqs-select"
                        styles={selectStylesBase}
                        noOptionsMessage={({ inputValue }) =>
                            inputValue.length < 1 ? 'Type at least 1 character...' : 'No patients found'
                        }
                    />
                </div>
            </div>
        </div>
    );
};

export default React.memo(PatientQuickSearch);

import { useState, useEffect } from 'react';
import type { ChangeEvent, FormEvent } from 'react';
import type { PaymentSaveData } from '@/types/api.types';
import { formatNumber } from '../../utils/formatters';
import { formatISODate } from '../../core/utils';

// Types
interface SetInfo {
    set_sequence?: number | null;
    Balance?: number | null;
    set_cost?: number | null;
    TotalPaid?: number | null;
    currency?: string | null;
}

interface WorkInfo {
    workid?: number;
    // Add other work info fields as needed
}

interface PaymentFormData {
    amount_paid: string | number;
    date_of_payment: string;
}

interface FormErrors {
    amount_paid?: string | null;
    date_of_payment?: string | null;
    submit?: string;
}

interface PaymentFormDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (data: PaymentSaveData) => Promise<void>;
    set: SetInfo | null;
    workInfo?: WorkInfo;
}

const PaymentFormDrawer = ({ isOpen, onClose, onSave, set, workInfo: _workInfo }: PaymentFormDrawerProps) => {
    const [formData, setFormData] = useState<PaymentFormData>({
        amount_paid: 0,
        date_of_payment: formatISODate()
    });

    const [displayAmount, setDisplayAmount] = useState('');
    const [errors, setErrors] = useState<FormErrors>({});
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (isOpen && set) {
            // Reset form when drawer opens
            const initialAmount = set.Balance || set.set_cost || 0;
            setFormData({
                amount_paid: initialAmount,
                date_of_payment: formatISODate()
            });
            setDisplayAmount(initialAmount ? formatNumber(initialAmount) : '');
            setErrors({});
        }
    }, [isOpen, set]);

    const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));

        // Clear error for this field
        if (errors[name as keyof FormErrors]) {
            setErrors(prev => ({ ...prev, [name]: null }));
        }
    };

    // Handle amount input with formatting as you type
    const handleAmountChange = (value: string) => {
        const digits = value.replace(/[^\d]/g, '');
        const num = parseInt(digits, 10) || 0;
        setDisplayAmount(num ? num.toLocaleString('en-US') : '');
        setFormData(prev => ({ ...prev, amount_paid: num }));
        if (errors.amount_paid) {
            setErrors(prev => ({ ...prev, amount_paid: null }));
        }
    };

    const validate = (): boolean => {
        const newErrors: FormErrors = {};
        const amount = Number(formData.amount_paid) || 0;

        if (amount <= 0) {
            newErrors.amount_paid = 'Amount paid is required and must be greater than 0';
        }

        if (!formData.date_of_payment) {
            newErrors.date_of_payment = 'Payment date is required';
        }

        if (set && set.Balance != null && amount > set.Balance) {
            newErrors.amount_paid = `Amount cannot exceed balance of ${formatNumber(set.Balance)}`;
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleSubmit = async (e: FormEvent<HTMLFormElement> | React.MouseEvent<HTMLButtonElement>) => {
        e.preventDefault();

        if (!validate()) {
            return;
        }

        setSaving(true);

        try {
            await onSave({
                ...formData,
                amount_paid: Number(formData.amount_paid),
                actual_amount: null,
                actual_cur: set?.currency || 'USD',
                change: null
            });
            onClose();
        } catch (error) {
            console.error('Error saving payment:', error);
            setErrors({ submit: (error as Error).message || 'Failed to save payment' });
        } finally {
            setSaving(false);
        }
    };

    // Block dismissal (backdrop / X / Cancel) while a save is in flight so the
    // payment can't be abandoned mid-request.
    const handleClose = () => {
        if (!saving) onClose();
    };

    if (!isOpen) return null;

    const remainingBalance = set?.Balance || set?.set_cost || 0;
    const totalPaid = set?.TotalPaid || 0;
    const newBalance = remainingBalance - (Number(formData.amount_paid) || 0);
    const currency = set?.currency || 'USD';

    return (
        // eslint-disable-next-line jsx-a11y/no-static-element-interactions, jsx-a11y/click-events-have-key-events -- backdrop click-to-dismiss
        <div className="drawer-overlay" onClick={handleClose}>
            {/* eslint-disable-next-line jsx-a11y/no-static-element-interactions, jsx-a11y/click-events-have-key-events -- backdrop click-to-dismiss */}
            <div className="drawer-container aligner-payment-drawer" onClick={(e) => e.stopPropagation()}>
                <div className="drawer-header">
                    <h2>Add Payment</h2>
                    <button className="drawer-close-btn" onClick={handleClose} disabled={saving}>
                        <i className="fas fa-times"></i>
                    </button>
                </div>

                <div className="drawer-body">
                    {/* Payment Summary */}
                    <div className="aligner-payment-summary">
                        <div className="summary-header">
                            <h3>Set #{set?.set_sequence}</h3>
                            <span className="set-currency">{currency}</span>
                        </div>
                        <div className="summary-grid">
                            <div className="summary-item">
                                <span className="label">Set Cost</span>
                                <span className="value">{formatNumber(set?.set_cost || 0)}</span>
                            </div>
                            <div className="summary-item">
                                <span className="label">Total Paid</span>
                                <span className="value">{formatNumber(totalPaid)}</span>
                            </div>
                            <div className="summary-item highlight">
                                <span className="label">Balance Due</span>
                                <span className="value">{formatNumber(remainingBalance)}</span>
                            </div>
                        </div>
                    </div>

                    <form onSubmit={handleSubmit} className="aligner-payment-form">
                        {/* Amount Paid */}
                        <div className="form-field">
                            <label htmlFor="amount_paid">
                                Amount to Pay <span className="required">*</span>
                            </label>
                            <div className="input-group">
                                <input
                                    type="text"
                                    id="amount_paid"
                                    name="amount_paid"
                                    value={displayAmount}
                                    onChange={(e) => handleAmountChange(e.target.value)}
                                    onBlur={() => setDisplayAmount(formData.amount_paid ? formatNumber(formData.amount_paid) : '')}
                                    className={errors.amount_paid ? 'error' : ''}
                                    // eslint-disable-next-line jsx-a11y/no-autofocus -- intentional focus on open
                                    autoFocus
                                    placeholder="Enter amount"
                                />
                                <span className="currency-badge">{currency}</span>
                            </div>
                            {errors.amount_paid && <span className="error-message">{errors.amount_paid}</span>}
                        </div>

                        {/* Payment Date */}
                        <div className="form-field">
                            <label htmlFor="date_of_payment">
                                Payment Date <span className="required">*</span>
                            </label>
                            <input
                                type="date"
                                id="date_of_payment"
                                name="date_of_payment"
                                value={formData.date_of_payment}
                                onChange={handleChange}
                                className={errors.date_of_payment ? 'error' : ''}
                            />
                            {errors.date_of_payment && <span className="error-message">{errors.date_of_payment}</span>}
                        </div>

                        {/* New Balance Preview */}
                        {Number(formData.amount_paid) > 0 && (
                            <div className="balance-preview">
                                <span className="preview-label">New Balance:</span>
                                <span className={`preview-value ${newBalance <= 0 ? 'paid-full' : ''}`}>
                                    {formatNumber(newBalance)} {currency}
                                </span>
                                {newBalance <= 0 && <span className="badge-success">Fully Paid</span>}
                            </div>
                        )}

                        {errors.submit && (
                            <div className="error-alert">
                                <i className="fas fa-exclamation-circle"></i>
                                {errors.submit}
                            </div>
                        )}
                    </form>
                </div>

                <div className="drawer-footer">
                    <button type="button" className="btn-cancel" onClick={handleClose} disabled={saving}>
                        Cancel
                    </button>
                    <button
                        type="submit"
                        className="btn-submit"
                        onClick={handleSubmit}
                        disabled={saving}
                    >
                        {saving ? (
                            <>
                                <i className="fas fa-spinner fa-spin"></i>
                                Saving...
                            </>
                        ) : (
                            <>
                                <i className="fas fa-check"></i>
                                Save Payment
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PaymentFormDrawer;

