/**
 * PatientSlideshow — operator-controlled presentation builder + player.
 *
 * Lets staff hand-pick photos across a single patient's timepoints, arrange the
 * order, then play an immersive, touch-driven slideshow (for chair-side consults
 * and social-media reels). Frontend-only: reuses the existing timepoints/gallery
 * endpoints. The working sequence is mirrored to sessionStorage so it survives
 * navigating away and back within the session.
 */
import { useEffect, useRef, useState } from 'react';
import { useToast } from '../../../contexts/ToastContext';
import { generateId } from '../../../core/utils';
import { fetchJSON } from '@/core/http';
import * as patientContract from '@shared/contracts/patient.contract';
import SlideshowBuilder from './SlideshowBuilder';
import SlideshowPlayer from './SlideshowPlayer';
import { labelForImageName, isLogoImage } from './photoTypes';
import type { SlideItem, SlidePhoto, Timepoint } from './types';
import styles from './PatientSlideshow.module.css';

interface Props {
  personId?: number | null;
}

interface GalleryEntry {
  name: string;
  width?: number;
  height?: number;
  /** File mtime (ms) — appended as `?v=` to bust the cache when a slot is re-rendered. */
  mtime?: number;
}

/** Raw shape from GET /api/patients/:id/timepoints (snake_case API). */
interface TimepointApiRow {
  tp_code: string;
  tp_date_time: string;
  tp_description: string;
}

// dd-mm-yyyy, matching the convention used elsewhere (Navigation.formatDate).
function formatDate(dateTime: string): string {
  if (!dateTime) return '';
  return dateTime.substring(0, 10).split('-').reverse().join('-');
}

const sessionKey = (pid: number | null | undefined): string => `slideshow_seq_${pid ?? 'none'}`;

function readSession(pid: number | null | undefined): SlideItem[] {
  try {
    const raw = sessionStorage.getItem(sessionKey(pid));
    const parsed = raw ? JSON.parse(raw) : null;
    if (!Array.isArray(parsed)) return [];
    // Back-compat: legacy sessions stored a non-unique `id` and no `uid`.
    // Drop the old id and mint a unique instance id so duplicates can't collide.
    return parsed.map((s: Record<string, unknown>) => {
      const { id: _legacyId, uid, ...rest } = s;
      return { ...rest, uid: typeof uid === 'string' ? uid : generateId() } as SlideItem;
    });
  } catch {
    return [];
  }
}

function writeSession(pid: number | null | undefined, items: SlideItem[]): void {
  try {
    sessionStorage.setItem(sessionKey(pid), JSON.stringify(items));
  } catch {
    /* storage disabled / quota — non-fatal */
  }
}

// --- Slide/photo helpers (a slide carries one photo, or two when paired) ---
const toPhoto = (item: SlideItem): SlidePhoto => ({
  name: item.name,
  url: item.url,
  tp: item.tp,
  tpDescription: item.tpDescription,
  tpDate: item.tpDate,
  label: item.label,
});

// Wrap a palette photo as a fresh slide instance (unique uid → duplicates allowed).
const newSlide = (photo: SlidePhoto): SlideItem => ({ ...photo, uid: generateId() });

const withoutSecond = (slide: SlideItem): SlideItem => {
  const copy = { ...slide };
  delete copy.second;
  return copy;
};

const PatientSlideshow = ({ personId }: Props) => {
  const toast = useToast();

  const [timepoints, setTimepoints] = useState<Timepoint[]>([]);
  const [loadingTimepoints, setLoadingTimepoints] = useState(true);
  const [galleries, setGalleries] = useState<Record<string, SlidePhoto[]>>({});
  const [selected, setSelected] = useState<SlideItem[]>(() => readSession(personId));
  const [mode, setMode] = useState<'build' | 'play'>('build');

  // Load timepoints whenever the patient changes.
  useEffect(() => {
    if (!personId) {
      setLoadingTimepoints(false);
      return;
    }
    const ctrl = new AbortController();
    setLoadingTimepoints(true);
    fetchJSON<TimepointApiRow[]>(`/api/patients/${personId}/timepoints`, { signal: ctrl.signal, schema: patientContract.timepoints.response })
      .then((data) =>
        setTimepoints(
          Array.isArray(data)
            ? data.map((r) => ({
                tpCode: r.tp_code,
                tpDateTime: r.tp_date_time,
                tpDescription: r.tp_description,
              }))
            : []
        )
      )
      .catch((err) => {
        if (err.name !== 'AbortError') {
          toast.error('Failed to load photo sessions');
          setTimepoints([]);
        }
      })
      .finally(() => setLoadingTimepoints(false));
    return () => ctrl.abort();
  }, [personId, toast]);

  // Hydrate the sequence on patient change; otherwise persist it for this session.
  const pidRef = useRef(personId);
  useEffect(() => {
    if (pidRef.current !== personId) {
      pidRef.current = personId;
      setSelected(readSession(personId));
      setGalleries({});
      setMode('build');
      return;
    }
    writeSession(personId, selected);
  }, [personId, selected]);

  // Lazy-load a timepoint's gallery on first expand; cache the palette photos.
  const loadGallery = async (tp: Timepoint): Promise<SlidePhoto[]> => {
    if (galleries[tp.tpCode]) return galleries[tp.tpCode];
    if (!personId) return [];
    const raw = await fetchJSON<(GalleryEntry | null)[]>(`/api/patients/${personId}/gallery/${tp.tpCode}`, { schema: patientContract.gallery.response });
    const items: SlidePhoto[] = raw
      .filter((e): e is GalleryEntry => !!e && !isLogoImage(e.name))
      .map((e) => ({
        name: e.name,
        // Cache-bust with mtime so a re-rendered slot isn't served stale from cache.
        url: e.mtime ? `/DolImgs/${e.name}?v=${e.mtime}` : `/DolImgs/${e.name}`,
        tp: tp.tpCode,
        tpDescription: tp.tpDescription,
        tpDate: formatDate(tp.tpDateTime),
        label: labelForImageName(e.name),
      }));
    setGalleries((prev) => ({ ...prev, [tp.tpCode]: items }));
    return items;
  };

  // Gallery tap: append a fresh copy to the end (duplicates allowed).
  const addToSequence = (photo: SlidePhoto) => setSelected((prev) => [...prev, newSlide(photo)]);

  // Gallery drag → gap: insert a fresh copy at a specific position.
  const insertAt = (photo: SlidePhoto, index: number) =>
    setSelected((prev) => {
      const at = Math.max(0, Math.min(index, prev.length));
      const next = prev.slice();
      next.splice(at, 0, newSlide(photo));
      return next;
    });

  // Gallery drag → chip: make the target slide a side-by-side pair (right-hand photo).
  const pairPhotoOnto = (targetIndex: number, photo: SlidePhoto) =>
    setSelected((prev) => {
      const target = prev[targetIndex];
      if (!target) return prev;
      if (target.second) {
        toast.info('That slide already has two photos');
        return prev;
      }
      const next = prev.slice();
      next[targetIndex] = { ...target, second: { ...photo } };
      return next;
    });

  // Tray chip ✕ removes that one instance (both photos of a pair); use unpair to split.
  const removeSelect = (uid: string) => setSelected((prev) => prev.filter((s) => s.uid !== uid));

  // Chip drag → another chip: merge two single slides (target = left, dragged = right).
  const pairSlides = (fromIndex: number, toIndex: number) =>
    setSelected((prev) => {
      if (fromIndex === toIndex) return prev;
      const from = prev[fromIndex];
      const to = prev[toIndex];
      if (!from || !to) return prev;
      if (from.second || to.second) {
        toast.info('Both slides must be single to combine');
        return prev;
      }
      const next = prev.slice();
      next[toIndex] = { ...to, second: toPhoto(from) };
      next.splice(fromIndex, 1); // remove the dragged slide from its old slot
      return next;
    });

  // Split a paired slide back into two consecutive single slides.
  const unpair = (index: number) => {
    setSelected((prev) => {
      const slide = prev[index];
      if (!slide?.second) return prev;
      const next = prev.slice();
      next[index] = withoutSecond(slide);
      next.splice(index + 1, 0, newSlide(slide.second));
      return next;
    });
  };

  const clearSelect = () => setSelected([]);

  const moveSlide = (from: number, to: number) => {
    setSelected((prev) => {
      if (from === to || from < 0 || to < 0 || from >= prev.length || to >= prev.length) return prev;
      const next = prev.slice();
      const [moved] = next.splice(from, 1);
      next.splice(to, 0, moved);
      return next;
    });
  };

  const play = () => {
    if (selected.length === 0) return;
    setMode('play');
  };

  if (!personId) {
    return (
      <div className={styles.root}>
        <p className={styles.empty}>Select a patient to build a presentation.</p>
      </div>
    );
  }

  return (
    <div className={styles.root}>
      <SlideshowBuilder
        timepoints={timepoints}
        loadingTimepoints={loadingTimepoints}
        galleries={galleries}
        loadGallery={loadGallery}
        selected={selected}
        onAdd={addToSequence}
        onInsertAt={insertAt}
        onPairPhotoOnto={pairPhotoOnto}
        onReorder={moveSlide}
        onPairSlides={pairSlides}
        onRemove={removeSelect}
        onUnpair={unpair}
        onClear={clearSelect}
        onPlay={play}
      />
      {mode === 'play' && selected.length > 0 && (
        <SlideshowPlayer slides={selected} onExit={() => setMode('build')} />
      )}
    </div>
  );
};

export default PatientSlideshow;

/**
 * SlideshowPlayer — immersive, manually-driven presentation overlay.
 *
 * Renders fullscreen (with a fixed-overlay fallback if fullscreen is denied).
 * The operator advances by swipe, tap zones (left third = prev, right third =
 * next, center = toggle chrome), or arrow keys. Transitions are clean crossfade
 * or slide. Chrome auto-hides; a screen Wake Lock keeps the display awake.
 */
import { useEffect, useRef, useState } from 'react';
import type { PointerEvent as ReactPointerEvent, SyntheticEvent } from 'react';
import cn from 'classnames';
import { useFullscreen } from './useFullscreen';
import { useWakeLock } from './useWakeLock';
import type { Framing, SlideItem, SlidePhoto, TransitionStyle } from './types';
import styles from './SlideshowPlayer.module.css';

interface Props {
  slides: SlideItem[];
  onExit: () => void;
}

interface Outgoing {
  item: SlideItem;
  dir: 1 | -1;
  key: number;
}

const SWIPE_THRESHOLD = 50; // px before a horizontal drag counts as a swipe
const TAP_THRESHOLD = 10; // px of movement still treated as a tap
const CHROME_HIDE_MS = 2800;
const TRANSITION_MS = 420; // must exceed the CSS animation duration (--transition-slow)
const PLACEHOLDER = '/images/placeholder.svg';

const SlideshowPlayer = ({ slides, onExit }: Props) => {
  const stageRef = useRef<HTMLDivElement>(null);
  const { isFullscreen, enter, exit } = useFullscreen(stageRef);
  useWakeLock(true);

  const [reduceMotion] = useState(
    () => typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches,
  );

  const indexRef = useRef(0);
  const [index, setIndexState] = useState(0);
  const setIndex = (n: number) => {
    indexRef.current = n;
    setIndexState(n);
  };

  const [animKey, setAnimKey] = useState(0);
  const [direction, setDirection] = useState<1 | -1>(1);
  const [outgoing, setOutgoing] = useState<Outgoing | null>(null);
  const keyCounter = useRef(0);
  const clearTimerRef = useRef<number | undefined>(undefined);

  const [transition, setTransition] = useState<TransitionStyle>('crossfade');
  const [framing, setFraming] = useState<Framing>('fit');
  const [showCaption, setShowCaption] = useState(true);
  const [chromeVisible, setChromeVisible] = useState(true);
  const hideTimerRef = useRef<number | undefined>(undefined);

  const safeIndex = Math.min(index, slides.length - 1);
  const current = slides[safeIndex];

  // Enter fullscreen on mount; release timers on unmount.
  useEffect(() => {
    void enter();
    return () => {
      if (clearTimerRef.current) window.clearTimeout(clearTimerRef.current);
      if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
    };
  }, [enter]);

  // If the user leaves OS fullscreen (Esc / gesture) after we entered it, close.
  const wasFullscreenRef = useRef(false);
  useEffect(() => {
    if (isFullscreen) wasFullscreenRef.current = true;
    else if (wasFullscreenRef.current) {
      wasFullscreenRef.current = false;
      onExit();
    }
  }, [isFullscreen, onExit]);

  const revealChrome = () => {
    setChromeVisible(true);
    if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
    hideTimerRef.current = window.setTimeout(() => setChromeVisible(false), CHROME_HIDE_MS);
  };

  const hideChrome = () => {
    if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
    setChromeVisible(false);
  };

  // Reveal chrome on mount, then let it auto-hide.
  useEffect(() => {
    revealChrome();
     
  }, []);

  const go = (delta: 1 | -1) => {
    const cur = indexRef.current;
    const next = cur + delta;
    if (next < 0 || next >= slides.length) return;
    keyCounter.current += 1;
    if (!reduceMotion) {
      if (clearTimerRef.current) window.clearTimeout(clearTimerRef.current);
      setOutgoing({ item: slides[cur], dir: delta, key: keyCounter.current });
      clearTimerRef.current = window.setTimeout(() => setOutgoing(null), TRANSITION_MS);
    }
    setDirection(delta);
    setAnimKey(keyCounter.current);
    setIndex(next);
  };

  const handleExit = () => {
    if (document.fullscreenElement) {
      void exit(); // fullscreenchange handler will fire onExit
    } else {
      onExit();
    }
  };

  // Keyboard navigation (mouse/keyboard fallback).
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === ' ') {
        e.preventDefault(); // Space: suppress page scroll / focused-button activation
        go(1);
        revealChrome();
      } else if (e.key === 'ArrowLeft' || e.key === 'Backspace') {
        e.preventDefault(); // Backspace: suppress legacy history-back
        go(-1);
        revealChrome();
      } else if (e.key === 'Escape') {
        e.preventDefault();
        handleExit();
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [slides.length]);

  // Preload immediate neighbours for instant transitions.
  useEffect(() => {
    [safeIndex + 1, safeIndex - 1].forEach((i) => {
      if (i >= 0 && i < slides.length) {
        const img = new Image();
        img.src = slides[i].url;
        const sec = slides[i].second;
        if (sec) {
          const img2 = new Image();
          img2.src = sec.url;
        }
      }
    });
  }, [safeIndex, slides]);

  // --- Gesture handling on a dedicated layer (siblings of chrome buttons) ---
  const downRef = useRef<{ x: number; y: number; id: number; wasVisible: boolean } | null>(null);

  const onPointerDown = (e: ReactPointerEvent) => {
    downRef.current = { x: e.clientX, y: e.clientY, id: e.pointerId, wasVisible: chromeVisible };
  };

  const onPointerUp = (e: ReactPointerEvent) => {
    const down = downRef.current;
    downRef.current = null;
    if (!down || down.id !== e.pointerId) return;
    const dx = e.clientX - down.x;
    const dy = e.clientY - down.y;
    const absX = Math.abs(dx);
    const absY = Math.abs(dy);

    if (absX > SWIPE_THRESHOLD && absX > absY) {
      go(dx < 0 ? 1 : -1); // swipe left → next
      revealChrome();
      return;
    }
    if (absX < TAP_THRESHOLD && absY < TAP_THRESHOLD) {
      const rect = stageRef.current?.getBoundingClientRect();
      const rel = rect ? (e.clientX - rect.left) / rect.width : 0.5;
      if (rel < 0.33) {
        go(-1);
        revealChrome();
      } else if (rel > 0.67) {
        go(1);
        revealChrome();
      } else if (down.wasVisible) {
        hideChrome();
      } else {
        revealChrome();
      }
    }
  };

  const handleImgError = (e: SyntheticEvent<HTMLImageElement>) => {
    if (e.currentTarget.src.endsWith(PLACEHOLDER)) return;
    e.currentTarget.src = PLACEHOLDER;
  };

  const enterClass = !reduceMotion
    ? transition === 'crossfade'
      ? styles.enterFade
      : direction > 0
        ? styles.enterRight
        : styles.enterLeft
    : undefined;

  const leaveClass = (dir: 1 | -1) =>
    transition === 'crossfade' ? styles.leaveFade : dir > 0 ? styles.leaveLeft : styles.leaveRight;

  // Per-photo label for a paired (side-by-side) slide.
  const photoLabel = (photo: SlidePhoto) => (
    <span className={styles.pairLabel}>
      <span className={styles.pairLabelMain}>{photo.tpDescription || 'Photo'}</span>
      <span className={styles.pairLabelSub}>
        {photo.label}
        {photo.tpDate ? ` · ${photo.tpDate}` : ''}
      </span>
    </span>
  );

  // A slide renders one photo, or two side-by-side when `second` is set.
  const renderSlide = (item: SlideItem) => {
    if (!item.second) {
      return <img src={item.url} alt={item.label} draggable={false} onError={handleImgError} />;
    }
    return (
      <div className={styles.pair}>
        <div className={styles.pairItem}>
          <img src={item.url} alt={item.label} draggable={false} onError={handleImgError} />
          {showCaption && photoLabel(item)}
        </div>
        <div className={styles.pairItem}>
          <img src={item.second.url} alt={item.second.label} draggable={false} onError={handleImgError} />
          {showCaption && photoLabel(item.second)}
        </div>
      </div>
    );
  };

  if (!current) return null;

  return (
    <div ref={stageRef} className={styles.stage} role="dialog" aria-modal="true" aria-label="Presentation">
      <div className={cn(styles.frame, framing === 'reel' && styles.frameReel)}>
        {outgoing && (
          <div key={`out-${outgoing.key}`} className={cn(styles.layer, leaveClass(outgoing.dir))}>
            {renderSlide(outgoing.item)}
          </div>
        )}
        <div key={`in-${animKey}`} className={cn(styles.layer, enterClass)}>
          {renderSlide(current)}
        </div>

        {showCaption && !current.second && (
          <div className={styles.caption}>
            <span className={styles.captionMain}>{current.tpDescription || 'Photo'}</span>
            <span className={styles.captionSub}>
              {current.label}
              {current.tpDate ? ` · ${current.tpDate}` : ''}
            </span>
          </div>
        )}
      </div>

      {/* Gesture layer: catches taps/swipes everywhere except on chrome buttons. */}
      <div className={styles.gestureLayer} onPointerDown={onPointerDown} onPointerUp={onPointerUp} />

      <div className={cn(styles.chrome, !chromeVisible && styles.chromeHidden)}>
        <div className={styles.topBar}>
          <span className={styles.counter}>
            {safeIndex + 1} / {slides.length}
          </span>
          <div className={styles.controls}>
            <button
              type="button"
              className={cn(styles.iconBtn, framing === 'reel' && styles.iconBtnActive)}
              title={framing === 'reel' ? 'Reel 9:16 framing' : 'Fit to screen'}
              aria-label="Toggle framing"
              onClick={() => setFraming((f) => (f === 'fit' ? 'reel' : 'fit'))}
            >
              <i className={cn('fas', framing === 'reel' ? 'fa-mobile-screen-button' : 'fa-expand')} />
            </button>
            <button
              type="button"
              className={styles.iconBtn}
              title={transition === 'crossfade' ? 'Crossfade (tap for Slide)' : 'Slide (tap for Crossfade)'}
              aria-label="Toggle transition"
              onClick={() => setTransition((t) => (t === 'crossfade' ? 'slide' : 'crossfade'))}
            >
              <i className={cn('fas', transition === 'crossfade' ? 'fa-circle-half-stroke' : 'fa-arrows-left-right')} />
            </button>
            <button
              type="button"
              className={cn(styles.iconBtn, showCaption && styles.iconBtnActive)}
              title="Toggle caption"
              aria-label="Toggle caption"
              onClick={() => setShowCaption((c) => !c)}
            >
              <i className="fas fa-closed-captioning" />
            </button>
            <button
              type="button"
              className={cn(styles.iconBtn, styles.exitBtn)}
              title="Close (Esc)"
              aria-label="Close presentation"
              onClick={handleExit}
            >
              <i className="fas fa-times" />
            </button>
          </div>
        </div>

        {slides.length > 1 && slides.length <= 15 && (
          <div className={styles.dots}>
            {slides.map((s, i) => (
              <span key={s.uid} className={cn(styles.dot, i === safeIndex && styles.dotActive)} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default SlideshowPlayer;

