/**
 * ItemFormModal Component
 * Modal for adding or editing a stand inventory item
 */
import { useState, useEffect } from 'react';
import type { ChangeEvent, FormEvent } from 'react';
import type { StandItem, StandItemCreateData } from '../../hooks/useStand';
import { useStandCategories } from '../../hooks/useStand';
import { useToast } from '../../contexts/ToastContext';
import { formatNumber } from '../../utils/formatters';
import { postJSON, httpErrorMessage } from '@/core/http';
import { scanVision, type VisionScanResult } from '@shared/contracts/stand.contract';
import Modal from '../react/Modal';
import styles from './ItemFormModal.module.css';

interface ItemFormModalProps {
  isOpen: boolean;
  item: StandItem | null;
  onClose: () => void;
  onSave: (data: StandItemCreateData) => void | Promise<void>;
}

interface FormData {
  itemName: string;
  sku: string;
  barcode: string;
  categoryId: string;
  costPrice: number;
  sellPrice: number;
  currentStock: number;
  reorderLevel: number;
  expiryDate: string;
  unit: string;
  notes: string;
}

interface FormErrors {
  itemName?: string | null;
  costPrice?: string | null;
  sellPrice?: string | null;
  currentStock?: string | null;
}

function compressImage(file: File, maxWidth = 1024): Promise<string> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      URL.revokeObjectURL(url);
      const canvas = document.createElement('canvas');
      let { width, height } = img;
      if (width > maxWidth) {
        height = Math.round((height * maxWidth) / width);
        width = maxWidth;
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) { reject(new Error('Canvas context unavailable')); return; }
      ctx.drawImage(img, 0, 0, width, height);
      resolve(canvas.toDataURL('image/jpeg', 0.8));
    };
    img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('Failed to load image')); };
    img.src = url;
  });
}

async function detectBarcode(files: File[]): Promise<string | null> {
  if (typeof BarcodeDetector === 'undefined') return null;
  try {
    const detector = new BarcodeDetector({
      formats: ['ean_13', 'ean_8', 'upc_a', 'upc_e', 'code_128', 'code_39', 'qr_code'],
    });
    for (const file of files) {
      const bitmap = await createImageBitmap(file);
      const barcodes = await detector.detect(bitmap);
      bitmap.close();
      if (barcodes.length > 0) return barcodes[0].rawValue;
    }
  } catch {
    // BarcodeDetector not supported or detection failed — fall through
  }
  return null;
}

async function dataUrlToFile(dataUrl: string, name: string): Promise<File> {
  // eslint-disable-next-line no-restricted-syntax -- converts a data: URL to a Blob/File, not an API call
  const res = await fetch(dataUrl);
  const blob = await res.blob();
  return new File([blob], name, { type: blob.type || 'image/jpeg' });
}

const FORM_STORAGE_KEY = 'standInventory.itemForm';

interface PersistedFormState {
  itemId: number | null;
  formData: FormData;
  imageDataUrls: string[];
}

const UNIT_OPTIONS = ['piece', 'box', 'tube', 'bottle', 'pack'];

const DEFAULT_FORM: FormData = {
  itemName: '',
  sku: '',
  barcode: '',
  categoryId: '',
  costPrice: 0,
  sellPrice: 0,
  currentStock: 0,
  reorderLevel: 1,
  expiryDate: '',
  unit: '',
  notes: '',
};

export default function ItemFormModal({ isOpen, item, onClose, onSave }: ItemFormModalProps) {
  const { categories } = useStandCategories();
  const toast = useToast();
  const [formData, setFormData] = useState<FormData>({ ...DEFAULT_FORM });
  const [errors, setErrors] = useState<FormErrors>({});
  const [displayCost, setDisplayCost] = useState('');
  const [displaySell, setDisplaySell] = useState('');
  const [scanImages, setScanImages] = useState<File[]>([]);
  const [scanPreviews, setScanPreviews] = useState<string[]>([]);
  const [scanning, setScanning] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const isEditMode = !!item;

  useEffect(() => {
    if (!isOpen) {
      scanPreviews.forEach((url) => URL.revokeObjectURL(url));
      setScanImages([]);
      setScanPreviews([]);
      setScanning(false);
      sessionStorage.removeItem(FORM_STORAGE_KEY);
      return;
    }

    let restored: PersistedFormState | null = null;
    try {
      const saved = sessionStorage.getItem(FORM_STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved) as PersistedFormState;
        const currentId = item?.item_id ?? null;
        if (parsed.itemId === currentId) restored = parsed;
      }
    } catch {
      // ignore malformed storage
    }

    if (restored) {
      setFormData(restored.formData);
      setDisplayCost(restored.formData.costPrice ? formatNumber(restored.formData.costPrice) : '');
      setDisplaySell(restored.formData.sellPrice ? formatNumber(restored.formData.sellPrice) : '');
      if (restored.imageDataUrls.length > 0) {
        (async () => {
          try {
            const files = await Promise.all(
              restored!.imageDataUrls.map((url, i) => dataUrlToFile(url, `restored-${i}.jpg`))
            );
            setScanImages(files);
            setScanPreviews(files.map((f) => URL.createObjectURL(f)));
          } catch {
            // ignore — user can re-shoot
          }
        })();
      }
    } else if (item) {
      setFormData({
        itemName: item.item_name,
        sku: item.sku || '',
        barcode: item.barcode || '',
        categoryId: item.category_id != null ? String(item.category_id) : '',
        costPrice: item.cost_price,
        sellPrice: item.sell_price,
        currentStock: item.current_stock,
        reorderLevel: item.reorder_level,
        expiryDate: item.expiry_date ? item.expiry_date.split('T')[0] : '',
        unit: item.unit || '',
        notes: item.notes || '',
      });
      setDisplayCost(item.cost_price ? formatNumber(item.cost_price) : '');
      setDisplaySell(item.sell_price ? formatNumber(item.sell_price) : '');
    } else {
      setFormData({ ...DEFAULT_FORM });
      setDisplayCost('');
      setDisplaySell('');
    }
    setErrors({});
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen, item]);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    (async () => {
      try {
        const imageDataUrls = await Promise.all(
          scanImages.map((file) => compressImage(file, 1024))
        );
        if (cancelled) return;
        const payload: PersistedFormState = {
          itemId: item?.item_id ?? null,
          formData,
          imageDataUrls,
        };
        sessionStorage.setItem(FORM_STORAGE_KEY, JSON.stringify(payload));
      } catch {
        // quota exceeded or compression failed — tolerate
      }
    })();
    return () => { cancelled = true; };
  }, [isOpen, item, formData, scanImages]);

  const handleChange = (
    field: keyof FormData,
    value: string
  ) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field as keyof FormErrors]) {
      setErrors((prev) => ({ ...prev, [field]: null }));
    }
  };

  const handleAmountChange = (
    field: 'costPrice' | 'sellPrice',
    rawValue: string,
    setDisplay: (v: string) => void
  ) => {
    const digits = rawValue.replace(/[^\d]/g, '');
    const num = parseInt(digits, 10) || 0;
    setDisplay(num ? num.toLocaleString('en-US') : '');
    setFormData((prev) => ({ ...prev, [field]: num }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: null }));
    }
  };

  const matchCategory = (suggestion: string): string => {
    if (!suggestion || categories.length === 0) return '';
    const lower = suggestion.toLowerCase().trim();

    const exact = categories.find((c) => c.category_name.toLowerCase() === lower);
    if (exact) return String(exact.category_id);

    const partial = categories.find(
      (c) =>
        c.category_name.toLowerCase().includes(lower) ||
        lower.includes(c.category_name.toLowerCase())
    );
    if (partial) return String(partial.category_id);

    const suggestionWords = lower.split(/\s+/);
    let bestMatch: { id: number; score: number } | null = null;
    for (const cat of categories) {
      const catWords = cat.category_name.toLowerCase().split(/\s+/);
      const score = suggestionWords.filter((w) =>
        catWords.some((cw) => cw.includes(w) || w.includes(cw))
      ).length;
      if (score > 0 && (!bestMatch || score > bestMatch.score)) {
        bestMatch = { id: cat.category_id, score };
      }
    }
    if (bestMatch) return String(bestMatch.id);

    return '';
  };

  const handleImageSelect = (e: ChangeEvent<HTMLInputElement>) => {
    const newFiles = Array.from(e.target.files || []);
    if (newFiles.length === 0) return;
    const combined = [...scanImages, ...newFiles];
    if (combined.length > 3) {
      toast.warning('Maximum 3 images allowed');
      const allowed = newFiles.slice(0, 3 - scanImages.length);
      if (allowed.length === 0) return;
      setScanImages((prev) => [...prev, ...allowed]);
      setScanPreviews((prev) => [...prev, ...allowed.map((f) => URL.createObjectURL(f))]);
    } else {
      setScanImages(combined);
      setScanPreviews((prev) => [...prev, ...newFiles.map((f) => URL.createObjectURL(f))]);
    }
    // Reset input so the same file can be re-selected
    e.target.value = '';
  };

  const handleRemoveImage = (index: number) => {
    URL.revokeObjectURL(scanPreviews[index]);
    setScanImages((prev) => prev.filter((_, i) => i !== index));
    setScanPreviews((prev) => prev.filter((_, i) => i !== index));
  };

  const handleScanItem = async () => {
    if (scanImages.length === 0) {
      toast.warning('Please select at least one image');
      return;
    }

    try {
      setScanning(true);

      const base64Images = await Promise.all(
        scanImages.map((file) => compressImage(file, 1024))
      );

      // Run barcode detection (local, instant) in parallel with Gemini API call.
      // scan-vision is sendSuccess-enveloped → fetchJSON unwraps to VisionScanResult.
      const [localBarcode, scan] = await Promise.all([
        detectBarcode(scanImages),
        postJSON<VisionScanResult>('/api/stand/items/scan-vision', { images: base64Images }, { schema: scanVision.response }),
      ]);

      // Prefer local BarcodeDetector result over Gemini's AI-read barcode
      const barcode = localBarcode || scan.barcode;

      setFormData((prev) => ({
        ...prev,
        itemName: scan.item_name || prev.itemName,
        barcode: barcode || prev.barcode,
        expiryDate: scan.expiry_date || prev.expiryDate,
        unit: UNIT_OPTIONS.includes(scan.unit?.toLowerCase()) ? scan.unit.toLowerCase() : prev.unit,
        notes: scan.notes || prev.notes,
        categoryId: matchCategory(scan.CategorySuggestion) || prev.categoryId,
      }));

      toast.success('Item details extracted successfully! Please verify the fields.');
    } catch (err) {
      toast.error(httpErrorMessage(err, 'Failed to scan product'));
    } finally {
      setScanning(false);
    }
  };

  const validateForm = (): boolean => {
    const newErrors: FormErrors = {};

    if (!formData.itemName.trim()) {
      newErrors.itemName = 'Item name is required';
    }
    if (formData.costPrice < 0) {
      newErrors.costPrice = 'Cost price must be 0 or greater';
    }
    if (formData.sellPrice < 0) {
      newErrors.sellPrice = 'Sell price must be 0 or greater';
    }
    if (!isEditMode && formData.currentStock < 0) {
      newErrors.currentStock = 'Initial stock cannot be negative';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (submitting || !validateForm()) return;

    const data: StandItemCreateData = {
      itemName: formData.itemName.trim(),
      sku: formData.sku.trim() || null,
      barcode: formData.barcode.trim() || null,
      categoryId: formData.categoryId ? Number(formData.categoryId) : null,
      costPrice: formData.costPrice,
      sellPrice: formData.sellPrice,
      reorderLevel: formData.reorderLevel,
      expiryDate: formData.expiryDate || null,
      unit: formData.unit || null,
      notes: formData.notes.trim() || null,
    };

    if (!isEditMode) {
      data.currentStock = formData.currentStock;
    }

    setSubmitting(true);
    try {
      await onSave(data);
    } finally {
      setSubmitting(false);
    }
  };

  const handleClose = () => {
    setFormData({ ...DEFAULT_FORM });
    setDisplayCost('');
    setDisplaySell('');
    setErrors({});
    scanPreviews.forEach((url) => URL.revokeObjectURL(url));
    setScanImages([]);
    setScanPreviews([]);
    setScanning(false);
    sessionStorage.removeItem(FORM_STORAGE_KEY);
    onClose();
  };

  const profit = formData.sellPrice - formData.costPrice;

  return (
    <Modal
      isOpen={isOpen}
      onClose={handleClose}
      contentClassName={styles.modalContent}
      ariaLabelledBy="item-form-modal-title"
    >
        <div className={styles.modalHeader}>
          <h2 id="item-form-modal-title">{isEditMode ? 'Edit Item' : 'Add New Item'}</h2>
          <button className={styles.closeBtn} onClick={handleClose} aria-label="Close modal">
            &times;
          </button>
        </div>

        <form onSubmit={handleSubmit}>
          <div className={styles.modalBody}>
            {/* Vision Scanner — Add mode only */}
            {!isEditMode && (
              <div className={styles.visionScanner}>
                <div className={styles.visionHeader}>
                  <span className={styles.visionIcon}>&#128247;</span>
                  <span>Auto-Fill with AI</span>
                </div>
                <p className={styles.visionHint}>
                  Shoot or pick 1–3 photos of the product to auto-fill the form
                </p>
                <div className={styles.visionControls}>
                  <label className={styles.visionFileLabel}>
                    <input
                      type="file"
                      accept="image/*"
                      capture="environment"
                      onChange={handleImageSelect}
                      className={styles.visionFileInput}
                      disabled={scanning}
                    />
                    Take Photo
                  </label>
                  <label className={styles.visionFileLabel}>
                    <input
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={handleImageSelect}
                      className={styles.visionFileInput}
                      disabled={scanning}
                    />
                    Choose from Gallery
                  </label>
                  <button
                    type="button"
                    className={styles.visionScanBtn}
                    onClick={handleScanItem}
                    disabled={scanning || scanImages.length === 0}
                  >
                    {scanning ? (
                      <>
                        <span className={styles.spinner} />
                        Scanning...
                      </>
                    ) : (
                      'Scan Item'
                    )}
                  </button>
                </div>
                {scanPreviews.length > 0 && (
                  <div className={styles.visionPreviews}>
                    {scanPreviews.map((src, idx) => (
                      <div key={idx} className={styles.visionThumb}>
                        <img src={src} alt={`Preview ${idx + 1}`} />
                        <button
                          type="button"
                          className={styles.visionThumbRemove}
                          onClick={() => handleRemoveImage(idx)}
                          disabled={scanning}
                          aria-label="Remove image"
                        >
                          &times;
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Name */}
            <div className={styles.formGroup}>
              <label htmlFor="item-name">
                Name <span className={styles.required}>*</span>
              </label>
              <input
                type="text"
                id="item-name"
                className={`${styles.formInput} ${errors.itemName ? styles.inputError : ''}`}
                value={formData.itemName}
                onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('itemName', e.target.value)}
                placeholder="Item name"
              />
              {errors.itemName && <span className={styles.errorMessage}>{errors.itemName}</span>}
            </div>

            {/* SKU + Barcode */}
            <div className={styles.formRow}>
              <div className={styles.formGroup}>
                <label htmlFor="item-sku">SKU</label>
                <input
                  type="text"
                  id="item-sku"
                  className={styles.formInput}
                  value={formData.sku}
                  onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('sku', e.target.value)}
                  placeholder="SKU code"
                />
              </div>
              <div className={styles.formGroup}>
                <label htmlFor="item-barcode">Barcode</label>
                <input
                  type="text"
                  id="item-barcode"
                  className={styles.formInput}
                  value={formData.barcode}
                  onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('barcode', e.target.value)}
                  placeholder="Barcode"
                />
              </div>
            </div>

            {/* Category */}
            <div className={styles.formGroup}>
              <label htmlFor="item-category">Category</label>
              <select
                id="item-category"
                className={styles.formInput}
                value={formData.categoryId}
                onChange={(e: ChangeEvent<HTMLSelectElement>) => handleChange('categoryId', e.target.value)}
              >
                <option value="">Select Category</option>
                {categories.map((cat) => (
                  <option key={cat.category_id} value={cat.category_id}>
                    {cat.category_name}
                  </option>
                ))}
              </select>
            </div>

            {/* Cost + Sell + Profit */}
            <div className={styles.formRowThree}>
              <div className={styles.formGroup}>
                <label htmlFor="item-cost">
                  Cost Price (IQD) <span className={styles.required}>*</span>
                </label>
                <input
                  type="text"
                  id="item-cost"
                  className={`${styles.formInput} ${errors.costPrice ? styles.inputError : ''}`}
                  value={displayCost}
                  onChange={(e: ChangeEvent<HTMLInputElement>) =>
                    handleAmountChange('costPrice', e.target.value, setDisplayCost)
                  }
                  onBlur={() => setDisplayCost(formData.costPrice ? formatNumber(formData.costPrice) : '')}
                  placeholder="0"
                />
                {errors.costPrice && <span className={styles.errorMessage}>{errors.costPrice}</span>}
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="item-sell">
                  Sell Price (IQD) <span className={styles.required}>*</span>
                </label>
                <input
                  type="text"
                  id="item-sell"
                  className={`${styles.formInput} ${errors.sellPrice ? styles.inputError : ''}`}
                  value={displaySell}
                  onChange={(e: ChangeEvent<HTMLInputElement>) =>
                    handleAmountChange('sellPrice', e.target.value, setDisplaySell)
                  }
                  onBlur={() => setDisplaySell(formData.sellPrice ? formatNumber(formData.sellPrice) : '')}
                  placeholder="0"
                />
                {errors.sellPrice && <span className={styles.errorMessage}>{errors.sellPrice}</span>}
              </div>

              <div className={styles.formGroup}>
                <span>Profit</span>
                <div className={styles.profitDisplay}>
                  <span className={styles.profitLabel}>IQD</span>
                  <span className={`${styles.profitValue} ${profit < 0 ? styles.profitNegative : ''}`}>
                    {formatNumber(profit)}
                  </span>
                </div>
              </div>
            </div>

            {/* Initial Stock (add mode only) + Reorder Level */}
            <div className={styles.formRow}>
              {!isEditMode && (
                <div className={styles.formGroup}>
                  <label htmlFor="item-stock">Initial Stock</label>
                  <input
                    type="number"
                    id="item-stock"
                    className={`${styles.formInput} ${errors.currentStock ? styles.inputError : ''}`}
                    value={formData.currentStock}
                    onChange={(e: ChangeEvent<HTMLInputElement>) =>
                      setFormData((prev) => ({ ...prev, currentStock: parseInt(e.target.value, 10) || 0 }))
                    }
                    min="0"
                  />
                  {errors.currentStock && <span className={styles.errorMessage}>{errors.currentStock}</span>}
                </div>
              )}
              <div className={styles.formGroup}>
                <label htmlFor="item-reorder">Reorder Level</label>
                <input
                  type="number"
                  id="item-reorder"
                  className={styles.formInput}
                  value={formData.reorderLevel}
                  onChange={(e: ChangeEvent<HTMLInputElement>) =>
                    setFormData((prev) => ({ ...prev, reorderLevel: parseInt(e.target.value, 10) || 0 }))
                  }
                  min="0"
                />
              </div>
            </div>

            {/* Expiry + Unit */}
            <div className={styles.formRow}>
              <div className={styles.formGroup}>
                <label htmlFor="item-expiry">Expiry Date</label>
                <input
                  type="date"
                  id="item-expiry"
                  className={styles.formInput}
                  value={formData.expiryDate}
                  onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('expiryDate', e.target.value)}
                />
              </div>
              <div className={styles.formGroup}>
                <label htmlFor="item-unit">Unit</label>
                <select
                  id="item-unit"
                  className={styles.formInput}
                  value={formData.unit}
                  onChange={(e: ChangeEvent<HTMLSelectElement>) => handleChange('unit', e.target.value)}
                >
                  <option value="">Select Unit</option>
                  {UNIT_OPTIONS.map((u) => (
                    <option key={u} value={u}>
                      {u.charAt(0).toUpperCase() + u.slice(1)}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {/* Notes */}
            <div className={styles.formGroup}>
              <label htmlFor="item-notes">Notes</label>
              <textarea
                id="item-notes"
                rows={3}
                className={styles.formInput}
                value={formData.notes}
                onChange={(e: ChangeEvent<HTMLTextAreaElement>) => handleChange('notes', e.target.value)}
                placeholder="Additional notes..."
              />
            </div>
          </div>

          <div className={styles.modalFooter}>
            <button type="button" className="btn btn-secondary" onClick={handleClose} disabled={submitting}>
              Cancel
            </button>
            <button type="submit" className="btn btn-primary" disabled={submitting}>
              {submitting ? 'Saving…' : isEditMode ? 'Update Item' : 'Add Item'}
            </button>
          </div>
        </form>
    </Modal>
  );
}

