/**
 * WhatsApp Authentication Hook
 * Manages WhatsApp client authentication state via the shared SSE channel
 * and the REST initial-state endpoint.
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useGlobalState } from '../contexts/GlobalStateContext';
import { useToast } from '../contexts/ToastContext';
import sseWhatsapp from '../services/sse-whatsapp';
import { fetchJSON, postJSON, httpErrorMessage, type HttpError } from '@/core/http';
import * as whatsappContract from '@shared/contracts/whatsapp.contract';

// Authentication States
export const AUTH_STATES = {
  INITIALIZING: 'initializing',
  CONNECTING: 'connecting',
  CONNECTED: 'connected',
  CHECKING_SESSION: 'checking_session',
  QR_REQUIRED: 'qr_required',
  AUTHENTICATED: 'authenticated',
  ERROR: 'error',
  DISCONNECTED: 'disconnected',
} as const;

export type AuthState = (typeof AUTH_STATES)[keyof typeof AUTH_STATES];

// Configuration Constants
const CONFIG = {
  CLIENT_RESTART_DELAY_MS: 2000,
  LOGOUT_DELAY_MS: 1000,
  QR_REFRESH_DELAY_MS: 30000,
} as const;

/**
 * Initial state response from server
 */
interface InitialStateResponse {
  qr?: string;
  clientReady?: boolean;
  error?: string;
  [key: string]: unknown;
}

/**
 * Actions returned by the hook
 */
export interface WhatsAppAuthActions {
  handleRetry: () => void;
  handleRefreshQR: () => void;
  handleRestart: () => Promise<void>;
  handleDestroy: () => Promise<void>;
  handleLogout: () => Promise<void>;
  fetchQRCode: () => Promise<string | null>;
}

/**
 * Return type for useWhatsAppAuth hook
 */
export interface UseWhatsAppAuthReturn {
  authState: AuthState;
  clientReady: boolean;
  qrCode: string | null;
  error: string | null;
  connectionAttempts: number;
  actions: WhatsAppAuthActions;
}

export const useWhatsAppAuth = (): UseWhatsAppAuthReturn => {
  const navigate = useNavigate();
  const location = useLocation();
  const toast = useToast();

  const { whatsappQrCode: qrCode, whatsappClientReady: clientReady } = useGlobalState();

  const [authState, setAuthState] = useState<AuthState>(AUTH_STATES.INITIALIZING);
  const [error, setError] = useState<string | null>(null);
  const [connectionAttempts, setConnectionAttempts] = useState(0);

  const qrRefreshTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Handle initial state - now only manages authState, not qrCode/clientReady
  const handleInitialState = useCallback((data: InitialStateResponse) => {
    if (!data) return;

    // qrCode and clientReady are managed by GlobalStateContext
    if (data.clientReady) {
      setAuthState(AUTH_STATES.AUTHENTICATED);
    } else if (data.qr) {
      setAuthState((currentState) =>
        currentState === AUTH_STATES.QR_REQUIRED ||
        currentState === AUTH_STATES.AUTHENTICATED
          ? currentState
          : AUTH_STATES.CHECKING_SESSION
      );

      setTimeout(() => {
        setAuthState((currentState) =>
          currentState === AUTH_STATES.CHECKING_SESSION
            ? AUTH_STATES.QR_REQUIRED
            : currentState
        );
      }, 3000);
    } else if (data.error) {
      setAuthState(AUTH_STATES.ERROR);
      setError(data.error);
    } else {
      // No QR and no clientReady — wait briefly for the client to settle.
      setAuthState((currentState) =>
        currentState === AUTH_STATES.QR_REQUIRED ||
        currentState === AUTH_STATES.AUTHENTICATED
          ? currentState
          : AUTH_STATES.CHECKING_SESSION
      );

      setTimeout(() => {
        setAuthState((currentState) =>
          currentState === AUTH_STATES.CHECKING_SESSION
            ? AUTH_STATES.QR_REQUIRED
            : currentState
        );
      }, 3000);
    }
  }, []);

  // Fetch initial state via REST (replaces the WS RPC).
  const requestInitialState = useCallback(async () => {
    try {
      // Flat `{ success, qr, clientReady, … }` (no `data` key) → fetchJSON passthrough.
      const data = await fetchJSON<InitialStateResponse>('/api/wa/initial-state', { schema: whatsappContract.initialState.response });
      handleInitialState(data);
    } catch (err) {
      console.error('[useWhatsAppAuth] initial-state fetch failed', err);
    }
  }, [handleInitialState]);

  // Fetch QR code from API (fallback method)
  const fetchQRCode = useCallback(async (): Promise<string | null> => {
    try {
      // Flat `{ qr, status, … }` (no `data` key) → fetchJSON passthrough.
      const qrResponse = await fetchJSON<{ qr?: string }>('/api/wa/qr', { schema: whatsappContract.qr.response });
      return qrResponse.qr || null;
    } catch (err) {
      // 404 = QR not available yet (a normal signal, not an error).
      if ((err as HttpError).status === 404) return null;
      console.error('Failed to fetch QR code:', err);
      return null;
    }
  }, []);

  // React to qrCode / clientReady arriving from GlobalStateContext (via the
  // whatsapp_qr_updated and whatsapp_client_ready SSE events).
  useEffect(() => {
    if (clientReady) {
      setAuthState(AUTH_STATES.AUTHENTICATED);
    } else if (qrCode) {
      setAuthState((currentState) =>
        currentState === AUTH_STATES.AUTHENTICATED
          ? currentState
          : AUTH_STATES.QR_REQUIRED
      );
    }
  }, [qrCode, clientReady]);

  // Subscribe to SSE lifecycle events + prime initial state on mount/reconnect.
  useEffect(() => {
    const handleConnected = () => {
      setAuthState(AUTH_STATES.CONNECTED);
      setConnectionAttempts(0);
      void requestInitialState();
    };

    const handleConnecting = () => {
      setAuthState((prev) =>
        prev === AUTH_STATES.AUTHENTICATED || prev === AUTH_STATES.QR_REQUIRED
          ? prev
          : AUTH_STATES.CONNECTING
      );
    };

    const handleDisconnected = () => {
      setAuthState(AUTH_STATES.DISCONNECTED);
    };

    const handleError = () => {
      setAuthState(AUTH_STATES.ERROR);
      setError('SSE connection failed');
    };

    const handleReconnected = () => {
      setConnectionAttempts(0);
      void requestInitialState();
    };

    sseWhatsapp.on('connecting', handleConnecting);
    sseWhatsapp.on('connected', handleConnected);
    sseWhatsapp.on('disconnected', handleDisconnected);
    sseWhatsapp.on('error', handleError);
    sseWhatsapp.on('reconnected', handleReconnected);

    sseWhatsapp
      .ensureConnected()
      .then(() => {
        void requestInitialState();
      })
      .catch((err) => {
        console.error('[useWhatsAppAuth] Failed to open SSE:', err);
        setAuthState(AUTH_STATES.ERROR);
        setError('Failed to open SSE connection');
      });

    return () => {
      sseWhatsapp.off('connecting', handleConnecting);
      sseWhatsapp.off('connected', handleConnected);
      sseWhatsapp.off('disconnected', handleDisconnected);
      sseWhatsapp.off('error', handleError);
      sseWhatsapp.off('reconnected', handleReconnected);
      sseWhatsapp.release();
    };
  }, [requestInitialState]);

  // Start / stop QR refresh timer
  const startQRRefreshTimer = useCallback(() => {
    if (qrRefreshTimerRef.current) clearInterval(qrRefreshTimerRef.current);
    qrRefreshTimerRef.current = setInterval(() => {
      if (authState === AUTH_STATES.QR_REQUIRED) {
        void requestInitialState();
      }
    }, CONFIG.QR_REFRESH_DELAY_MS);
  }, [authState, requestInitialState]);

  const stopQRRefreshTimer = useCallback(() => {
    if (qrRefreshTimerRef.current) {
      clearInterval(qrRefreshTimerRef.current);
      qrRefreshTimerRef.current = null;
    }
  }, []);

  // Action handlers
  const handleRetry = useCallback(() => {
    setAuthState(AUTH_STATES.INITIALIZING);
    setConnectionAttempts(0);
    setError(null);
    void requestInitialState();
  }, [requestInitialState]);

  const handleRefreshQR = useCallback(() => {
    void requestInitialState();
  }, [requestInitialState]);

  const handleRestart = useCallback(async () => {
    toast.info('Restarting WhatsApp client…');
    try {
      // Non-2xx now throws (route 500s on failure); the success body is success:true.
      await postJSON('/api/wa/restart', {});
      setAuthState(AUTH_STATES.INITIALIZING);
      toast.success('WhatsApp client restart initiated');
      setTimeout(() => {
        void requestInitialState();
      }, CONFIG.CLIENT_RESTART_DELAY_MS);
    } catch (err) {
      console.error('Restart failed:', err);
      setAuthState(AUTH_STATES.ERROR);
      const message = httpErrorMessage(err, 'Restart failed');
      setError(message);
      toast.error(`Restart failed: ${message}`);
    }
  }, [requestInitialState, toast]);

  const handleDestroy = useCallback(async () => {
    toast.info('Closing WhatsApp browser…');
    try {
      // Non-2xx now throws (route 400/500s on failure); the success body is success:true.
      await postJSON('/api/wa/destroy', {});
      setAuthState(AUTH_STATES.INITIALIZING);
      toast.success('WhatsApp browser closed');
    } catch (err) {
      console.error('Destroy failed:', err);
      setAuthState(AUTH_STATES.ERROR);
      const message = httpErrorMessage(err, 'Destroy failed');
      setError(message);
      toast.error(`Failed to close browser: ${message}`);
    }
  }, [toast]);

  const handleLogout = useCallback(async () => {
    toast.info('Logging out of WhatsApp…');
    try {
      // Non-2xx now throws (route 400/500s on failure); the success body is success:true.
      await postJSON('/api/wa/logout', {});
      setAuthState(AUTH_STATES.INITIALIZING);
      toast.success('Logged out — restarting client');

      // Re-prime initial state whether or not the follow-up restart succeeds
      // (both branches re-prime; the catch covers a non-2xx restart too).
      try {
        await postJSON('/api/wa/restart', {});
      } catch (restartError) {
        console.warn('Restart failed:', restartError);
      } finally {
        setTimeout(() => {
          void requestInitialState();
        }, CONFIG.LOGOUT_DELAY_MS);
      }
    } catch (err) {
      console.error('Logout failed:', err);
      setAuthState(AUTH_STATES.ERROR);
      const message = httpErrorMessage(err, 'Logout failed');
      setError(message);
      toast.error(`Logout failed: ${message}`);
    }
  }, [requestInitialState, toast]);

  // Sync authState with global qrCode and clientReady values
  useEffect(() => {
    if (clientReady && authState !== AUTH_STATES.AUTHENTICATED) {
      setAuthState(AUTH_STATES.AUTHENTICATED);
    } else if (!clientReady && qrCode && authState === AUTH_STATES.AUTHENTICATED) {
      setAuthState(AUTH_STATES.QR_REQUIRED);
    } else if (qrCode && authState === AUTH_STATES.CHECKING_SESSION) {
      setAuthState(AUTH_STATES.QR_REQUIRED);
    }
  }, [clientReady, qrCode, authState]);

  // Manage QR refresh timer based on auth state
  useEffect(() => {
    if (authState === AUTH_STATES.QR_REQUIRED) {
      startQRRefreshTimer();
    } else {
      stopQRRefreshTimer();
    }
    // Clear the interval on unmount — otherwise it keeps firing
    // requestInitialState() forever if the component unmounts while in
    // QR_REQUIRED state.
    return () => stopQRRefreshTimer();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authState]);

  // Handle page visibility — re-prime initial state on tab return.
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && authState === AUTH_STATES.QR_REQUIRED) {
        void requestInitialState();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authState]);

  // Auto-redirect only when the user actually went through QR scan on this
  // page. If the page mounted with the client already ready, stay so the user
  // can reach Restart / Close Browser / Logout.
  const sawQrStateRef = useRef(false);
  useEffect(() => {
    if (authState === AUTH_STATES.QR_REQUIRED) {
      sawQrStateRef.current = true;
    }
  }, [authState]);

  useEffect(() => {
    if (authState !== AUTH_STATES.AUTHENTICATED) return;
    if (!sawQrStateRef.current) return;

    const state = location.state as { returnPath?: string } | null;
    const returnPath = state?.returnPath || '/send';

    const timer = setTimeout(() => {
      navigate(returnPath, { replace: true });
    }, 2000);
    return () => clearTimeout(timer);
  }, [authState, location.state, navigate]);

  return {
    authState,
    clientReady,
    qrCode,
    error,
    connectionAttempts,
    actions: {
      handleRetry,
      handleRefreshQR,
      handleRestart,
      handleDestroy,
      handleLogout,
      fetchQRCode,
    },
  };
};

/**
 * Custom hook for WhatsApp send-page state (replaces the WS waStatus channel).
 * Subscribes to the shared SSE singleton and primes initial state via REST.
 */
import { useState, useEffect, useRef, useCallback } from 'react';
import { fetchJSON } from '@/core/http';
import * as whatsappContract from '@shared/contracts/whatsapp.contract';
import { useGlobalState } from '../contexts/GlobalStateContext';
import { UI_STATES, type UIState } from '../utils/whatsapp-send-constants';
import sseWhatsapp from '../services/sse-whatsapp';

/**
 * Sending progress data
 */
export interface SendingProgress {
  started: boolean;
  finished: boolean;
  total: number;
  sent: number;
  failed: number;
}

/**
 * Message status update data from the WhatsApp channel
 */
export interface MessageStatusUpdateData {
  date?: string;
  patientId?: number;
  status?: number;
  messageId?: string;
  [key: string]: unknown;
}

/**
 * Initial state response from server
 */
interface InitialStateResponse {
  clientReady?: boolean;
  sendingProgress?: SendingProgress;
  qr?: string;
  [key: string]: unknown;
}

/**
 * Return type for useWhatsAppSync hook
 */
export interface UseWhatsAppSyncReturn {
  connectionStatus: UIState;
  clientReady: boolean;
  sendingProgress: SendingProgress;
  messageStatusUpdate: MessageStatusUpdateData | null;
  requestInitialState: (dateToRequest?: string) => void;
}

export function useWhatsAppSync(currentDate: string): UseWhatsAppSyncReturn {
  const { whatsappClientReady: clientReady } = useGlobalState();

  const [connectionStatus, setConnectionStatus] = useState<UIState>(UI_STATES.DISCONNECTED);
  const [sendingProgress, setSendingProgress] = useState<SendingProgress>({
    started: false,
    finished: false,
    total: 0,
    sent: 0,
    failed: 0,
  });
  const [messageStatusUpdate, setMessageStatusUpdate] = useState<MessageStatusUpdateData | null>(
    null
  );

  const currentDateRef = useRef(currentDate);
  const lastRequestedDateRef = useRef<string | null>(null);

  useEffect(() => {
    currentDateRef.current = currentDate;
  }, [currentDate]);

  const applyInitialState = useCallback((data: InitialStateResponse | null) => {
    if (!data) return;
    if (data.sendingProgress && data.sendingProgress.started && !data.sendingProgress.finished) {
      setSendingProgress(data.sendingProgress);
    } else if (data.sendingProgress && data.sendingProgress.finished) {
      setSendingProgress({
        started: false,
        finished: false,
        total: 0,
        sent: 0,
        failed: 0,
      });
    }
  }, []);

  // Fetch initial state via REST (replaces the WS RPC). Preserves the
  // per-date dedupe so a date-change effect doesn't re-fire for the same
  // date during quick re-renders. The date is an explicit (optional) arg:
  // synchronous date-driven callers pass the fresh value directly, while
  // async SSE handlers omit it and fall back to the latest-date ref.
  const requestInitialState = useCallback((dateToRequest: string = currentDateRef.current) => {
    if (!dateToRequest) return;
    if (lastRequestedDateRef.current === dateToRequest) {
      return;
    }
    lastRequestedDateRef.current = dateToRequest;

    fetchJSON<InitialStateResponse>('/api/wa/initial-state', { schema: whatsappContract.initialState.response })
      .then(applyInitialState)
      .catch((err) => {
        console.error('[useWhatsAppSync] initial-state fetch failed', err);
        // Clear the dedupe key so a later trigger can retry this date.
        // Guarded so we don't clobber a newer in-flight request for another date.
        if (lastRequestedDateRef.current === dateToRequest) {
          lastRequestedDateRef.current = null;
        }
      });
  }, [applyInitialState]);

  // Subscribe to SSE lifecycle + event payloads on mount.
  useEffect(() => {
    const handleConnecting = () => setConnectionStatus(UI_STATES.CONNECTING);
    const handleConnected = () => {
      setConnectionStatus(UI_STATES.CONNECTED);
      requestInitialState();
    };
    const handleDisconnected = () => setConnectionStatus(UI_STATES.DISCONNECTED);
    const handleError = () => setConnectionStatus(UI_STATES.ERROR);
    const handleReconnected = () => {
      // Force a refresh on reconnect by clearing the dedupe.
      lastRequestedDateRef.current = null;
      requestInitialState();
    };

    const handleMessageStatus = (data: unknown) => {
      setMessageStatusUpdate(data as MessageStatusUpdateData);
    };

    const handleSendingStarted = (data: unknown) => {
      const typed = data as Partial<SendingProgress>;
      setSendingProgress({
        started: true,
        finished: false,
        total: typed.total || 0,
        sent: typed.sent || 0,
        failed: typed.failed || 0,
      });
    };

    const handleSendingProgress = (data: unknown) => {
      const typed = data as Partial<SendingProgress>;
      setSendingProgress((prev) => ({
        ...prev,
        sent: typed.sent || 0,
        failed: typed.failed || 0,
        finished: typed.finished || false,
      }));
    };

    const handleSendingFinished = () => {
      setSendingProgress((prev) => ({
        ...prev,
        finished: true,
      }));
    };

    sseWhatsapp.on('connecting', handleConnecting);
    sseWhatsapp.on('connected', handleConnected);
    sseWhatsapp.on('disconnected', handleDisconnected);
    sseWhatsapp.on('error', handleError);
    sseWhatsapp.on('reconnected', handleReconnected);
    sseWhatsapp.on('whatsapp_message_status', handleMessageStatus);
    sseWhatsapp.on('whatsapp_sending_started', handleSendingStarted);
    sseWhatsapp.on('whatsapp_sending_progress', handleSendingProgress);
    sseWhatsapp.on('whatsapp_sending_finished', handleSendingFinished);

    setConnectionStatus(UI_STATES.CONNECTING);
    sseWhatsapp
      .ensureConnected()
      .then(() => {
        setConnectionStatus(UI_STATES.CONNECTED);
        requestInitialState();
      })
      .catch((err) => {
        console.error('[useWhatsAppSync] Failed to open SSE:', err);
        setConnectionStatus(UI_STATES.ERROR);
      });

    return () => {
      sseWhatsapp.off('connecting', handleConnecting);
      sseWhatsapp.off('connected', handleConnected);
      sseWhatsapp.off('disconnected', handleDisconnected);
      sseWhatsapp.off('error', handleError);
      sseWhatsapp.off('reconnected', handleReconnected);
      sseWhatsapp.off('whatsapp_message_status', handleMessageStatus);
      sseWhatsapp.off('whatsapp_sending_started', handleSendingStarted);
      sseWhatsapp.off('whatsapp_sending_progress', handleSendingProgress);
      sseWhatsapp.off('whatsapp_sending_finished', handleSendingFinished);
      sseWhatsapp.release();
      lastRequestedDateRef.current = null;
    };
  }, [requestInitialState]);

  // Request initial state when date changes (transport stays connected).
  // Pass `currentDate` explicitly so this doesn't depend on the ref-updater
  // effect having run first — no ordering fragility.
  useEffect(() => {
    if (connectionStatus === UI_STATES.CONNECTED && currentDate) {
      requestInitialState(currentDate);
    }
  }, [currentDate, connectionStatus, requestInitialState]);

  return {
    connectionStatus,
    clientReady,
    sendingProgress,
    messageStatusUpdate,
    requestInitialState,
  };
}

import { useState, useEffect, type ChangeEvent } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { useToast } from '../contexts/ToastContext';
import { useConfirm } from '../contexts/ConfirmContext';
import styles from './Diagnosis.module.css';
import { formatISODate } from '../core/utils';
import { fetchJSON, postJSON, deleteJSON } from '@/core/http';
import { patientInfoQuery, worksQuery } from '@/query/queries';

/**
 * Diagnosis Page
 * Comprehensive diagnosis and treatment plan page with tabbed interface
 * Route: /patient/:personId/work/:workId/diagnosis
 */

interface DiagnosisData {
    work_id: number;
    dx_date: string;
    diagnosis: string;
    treatment_plan: string;
    chief_complain: string;
    appliance: string;
    // Facial Analysis
    f_antero_posterior: string;
    f_vertical: string;
    f_transverse: string;
    f_lip_competence: string;
    f_naso_labial_angle: string;
    f_upper_incisor_show_rest: string;
    f_upper_incisor_show_smile: string;
    // Intraoral Analysis
    i_teeth_present: string;
    i_dental_health: string;
    i_lower_crowding: string;
    i_lower_incisor_inclination: string;
    i_curveof_spee: string;
    i_upper_crowding: string;
    i_upper_incisor_inclination: string;
    // Occlusion Analysis
    o_incisor_relation: string;
    o_overjet: string;
    o_overbite: string;
    o_centerlines: string;
    o_molar_relation: string;
    o_canine_relation: string;
    o_functional_occlusion: string;
    // Cephalometric Analysis
    c_sna: string;
    c_snb: string;
    c_anb: string;
    c_sn_mx: string;
    c_wits: string;
    c_fma: string;
    c_mma: string;
    c_uimx: string;
    c_li_md: string;
    c_ui_li: string;
    c_li_a_po: string;
    c_ulip_e: string;
    c_llip_e: string;
    c_naso_lip: string;
    c_tafh: string;
    c_uafh: string;
    c_lafh: string;
    c_percent_lafh: string;
}

interface PatientInfo {
    patient_name?: string;
    name?: string;
    person_id?: number;
    [key: string]: unknown;
}

interface WorkInfo {
    work_id: number;
    type_name?: string;
    [key: string]: unknown;
}

interface Tab {
    id: string;
    label: string;
    icon: string;
}

type TabId = 'general' | 'facial' | 'intraoral' | 'occlusion' | 'cephalometric';

const Diagnosis = () => {
    const { personId, workId } = useParams<{ personId: string; workId: string }>();
    const navigate = useNavigate();
    const toast = useToast();
    const confirm = useConfirm();

    const [saving, setSaving] = useState(false);
    const [deleting, setDeleting] = useState(false);
    const [activeTab, setActiveTab] = useState<TabId>('general');
    const [diagnosisExists, setDiagnosisExists] = useState(false);
    // Diagnosis row read stays raw/schema-less by design (see effect below); its
    // own loading flag gates the page spinner alongside the two RQ reads.
    const [diagnosisLoading, setDiagnosisLoading] = useState(true);

    // Patient info + works reads on useQuery (the patientShellLoader prefetched
    // patientInfo, so it resolves from cache instantly). Loose contracts model
    // only key fields, so cast each to its concrete local type.
    const { data: patientData, isLoading: patientLoading } = useQuery({
        ...patientInfoQuery(personId ?? ''),
        enabled: !!personId,
    });
    const { data: worksData, isLoading: worksLoading } = useQuery({
        ...worksQuery(personId ?? ''),
        enabled: !!personId,
    });

    const patientInfo = (patientData ?? null) as unknown as PatientInfo | null;
    const works = (worksData ?? null) as unknown as WorkInfo[] | null;
    const workInfo = works
        ? works.find(w => w.work_id === parseInt(workId || '0')) ?? null
        : null;

    const loading = patientLoading || worksLoading || diagnosisLoading;

    const [diagnosisData, setDiagnosisData] = useState<DiagnosisData>({
        work_id: parseInt(workId || '0'),
        dx_date: formatISODate(),
        diagnosis: '',
        treatment_plan: '',
        chief_complain: '',
        appliance: '',
        // Facial Analysis
        f_antero_posterior: '',
        f_vertical: '',
        f_transverse: '',
        f_lip_competence: '',
        f_naso_labial_angle: '',
        f_upper_incisor_show_rest: '',
        f_upper_incisor_show_smile: '',
        // Intraoral Analysis
        i_teeth_present: '',
        i_dental_health: '',
        i_lower_crowding: '',
        i_lower_incisor_inclination: '',
        i_curveof_spee: '',
        i_upper_crowding: '',
        i_upper_incisor_inclination: '',
        // Occlusion Analysis
        o_incisor_relation: '',
        o_overjet: '',
        o_overbite: '',
        o_centerlines: '',
        o_molar_relation: '',
        o_canine_relation: '',
        o_functional_occlusion: '',
        // Cephalometric Analysis
        c_sna: '',
        c_snb: '',
        c_anb: '',
        c_sn_mx: '',
        c_wits: '',
        c_fma: '',
        c_mma: '',
        c_uimx: '',
        c_li_md: '',
        c_ui_li: '',
        c_li_a_po: '',
        c_ulip_e: '',
        c_llip_e: '',
        c_naso_lip: '',
        c_tafh: '',
        c_uafh: '',
        c_lafh: '',
        c_percent_lafh: ''
    });

    // Diagnosis row read — kept as a standalone raw fetch (patient info + works
    // now load via useQuery above). `/api/diagnosis/:workId` is DELIBERATELY
    // schema-less: it returns the row or literal `null` (the "no diagnosis yet"
    // signal) — not the sendSuccess envelope — so it stays out of the contract
    // and carries no client schema. Each GET stays independent via .catch(() => null)
    // (the N14 tolerant mechanic).
    useEffect(() => {
        let cancelled = false;
        setDiagnosisLoading(true);
        // eslint-disable-next-line no-restricted-syntax -- raw literal-null signal; no contract response
        fetchJSON<Partial<DiagnosisData> | null>(`/api/diagnosis/${workId}`)
            .catch(() => null)
            .then(diagnosis => {
                if (cancelled) return;
                if (diagnosis) {
                    // Format date to YYYY-MM-DD for input
                    if (diagnosis.dx_date) {
                        diagnosis.dx_date = formatISODate(diagnosis.dx_date);
                    }
                    setDiagnosisData(prev => ({ ...prev, ...diagnosis }));
                    setDiagnosisExists(true);
                }
            })
            .finally(() => {
                if (!cancelled) setDiagnosisLoading(false);
            });
        return () => { cancelled = true; };
    }, [workId]);

    const handleChange = (field: keyof DiagnosisData, value: string) => {
        setDiagnosisData(prev => ({ ...prev, [field]: value }));
    };

    const handleSave = async () => {
        // Validate required fields
        if (!diagnosisData.diagnosis.trim()) {
            toast.warning('Diagnosis is required');
            setActiveTab('general');
            return;
        }
        if (!diagnosisData.treatment_plan.trim()) {
            toast.warning('Treatment Plan is required');
            setActiveTab('general');
            return;
        }

        try {
            setSaving(true);
            await postJSON('/api/diagnosis', diagnosisData);

            toast.success('Diagnosis saved successfully');
            setDiagnosisExists(true);

            // Navigate back to the works list
            setTimeout(() => {
                navigate(`/patient/${personId}/works`);
            }, 500);
        } catch (err) {
            console.error('Error saving diagnosis:', err);
            toast.error('Failed to save diagnosis');
        } finally {
            setSaving(false);
        }
    };

    const handleCancel = () => {
        navigate(`/patient/${personId}/works`);
    };

    const handleReset = async () => {
        // Show confirmation
        const confirmMessage = `Are you sure you want to reset/delete this diagnosis?\n\nWork: ${workInfo?.type_name || 'N/A'}\nDate: ${diagnosisData.dx_date}\n\n⚠️ This action cannot be undone!`;

        if (!await confirm(confirmMessage, { title: 'Delete Diagnosis', danger: true, confirmText: 'Delete' })) return;

        try {
            setDeleting(true);
            await deleteJSON(`/api/diagnosis/${workId}`);

            toast.success('Diagnosis deleted successfully');

            // Navigate back to the works list
            setTimeout(() => {
                navigate(`/patient/${personId}/works`);
            }, 500);
        } catch (err) {
            console.error('Error deleting diagnosis:', err);
            toast.error('Failed to delete diagnosis');
        } finally {
            setDeleting(false);
        }
    };

    const tabs: Tab[] = [
        { id: 'general', label: 'General', icon: 'fas fa-clipboard-list' },
        { id: 'facial', label: 'Facial Analysis', icon: 'fas fa-user' },
        { id: 'intraoral', label: 'Intraoral', icon: 'fas fa-teeth' },
        { id: 'occlusion', label: 'Occlusion', icon: 'fas fa-grip-horizontal' },
        { id: 'cephalometric', label: 'Cephalometric', icon: 'fas fa-ruler-combined' }
    ];

    if (loading) {
        return (
            <div className={styles.diagnosisPage}>
                <div className={styles.diagnosisLoading}>
                    <i className="fas fa-spinner fa-spin"></i>
                    <span>Loading diagnosis data...</span>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.diagnosisPage}>
            {/* Page Header */}
            <div className={styles.diagnosisHeader}>
                <div className={styles.diagnosisHeaderContent}>
                    <button
                        type="button"
                        className={styles.btnBack}
                        onClick={handleCancel}
                        title="Back to work"
                    >
                        <i className="fas fa-arrow-left"></i>
                    </button>
                    <div className={styles.diagnosisHeaderInfo}>
                        <h1>
                            <i className="fas fa-stethoscope"></i>
                            Diagnosis & Treatment Plan
                        </h1>
                        <div className={styles.diagnosisMeta}>
                            {patientInfo && (
                                <span className={styles.patientName}>
                                    <i className="fas fa-user"></i>
                                    {patientInfo.patient_name || patientInfo.name}
                                </span>
                            )}
                            {workInfo && (
                                <span className={styles.workType}>
                                    <i className="fas fa-tooth"></i>
                                    {workInfo.type_name || 'Treatment'}
                                </span>
                            )}
                            <span className={styles.workId}>
                                <i className="fas fa-hashtag"></i>
                                Work ID: {workId}
                            </span>
                        </div>
                    </div>
                </div>
                <div className={styles.diagnosisHeaderActions}>
                    <button
                        type="button"
                        className={styles.btnCancel}
                        onClick={handleCancel}
                        disabled={saving || deleting}
                    >
                        <i className="fas fa-times"></i>
                        Cancel
                    </button>
                    {diagnosisExists && (
                        <button
                            type="button"
                            className={`btn-delete ${styles.deleteButton}`}
                            onClick={handleReset}
                            disabled={saving || deleting}
                        >
                            {deleting ? (
                                <>
                                    <i className="fas fa-spinner fa-spin"></i>
                                    Deleting...
                                </>
                            ) : (
                                <>
                                    <i className="fas fa-trash"></i>
                                    Reset Diagnosis
                                </>
                            )}
                        </button>
                    )}
                    <button
                        type="button"
                        className={styles.btnSave}
                        onClick={handleSave}
                        disabled={saving || deleting}
                    >
                        {saving ? (
                            <>
                                <i className="fas fa-spinner fa-spin"></i>
                                Saving...
                            </>
                        ) : (
                            <>
                                <i className="fas fa-save"></i>
                                Save Diagnosis
                            </>
                        )}
                    </button>
                </div>
            </div>

            {/* Tab Navigation */}
            <div className={styles.diagnosisTabs}>
                {tabs.map(tab => (
                    <button
                        key={tab.id}
                        type="button"
                        className={`${styles.diagnosisTab} ${activeTab === tab.id ? styles.diagnosisTabActive : ''}`}
                        onClick={() => setActiveTab(tab.id as TabId)}
                    >
                        <i className={tab.icon}></i>
                        <span>{tab.label}</span>
                    </button>
                ))}
            </div>

            {/* Tab Content */}
            <div className={styles.diagnosisContent}>
                {/* General Tab */}
                {activeTab === 'general' && (
                    <div className={styles.diagnosisTabContent}>
                        <h2 className={styles.sectionTitle}>General Information</h2>
                        <div className={styles.formGrid}>
                            <div className={styles.formGroup}>
                                <label htmlFor="dx-date">Diagnosis Date</label>
                                <input
                                    id="dx-date"
                                    type="date"
                                    className={styles.formInput}
                                    value={diagnosisData.dx_date}
                                    onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('dx_date', e.target.value)}
                                />
                            </div>

                            <div className={styles.formGroup}>
                                <label htmlFor="dx-appliance">Appliance</label>
                                <input
                                    id="dx-appliance"
                                    type="text"
                                    className={styles.formInput}
                                    value={diagnosisData.appliance || ''}
                                    onChange={(e: ChangeEvent<HTMLInputElement>) => handleChange('appliance', e.target.value)}
                                    placeholder="e.g., Roth, MBT, Damon..."
                                />
                            </div>

                            <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                                <label htmlFor="dx-chief-complain">Chief Complaint</label>
                                <textarea
                                    id="dx-chief-complain"
                                    className={styles.formTextarea}
                                    rows={3}
                                    value={diagnosisData.chief_complain || ''}
                                    onChange={(e: ChangeEvent<HTMLTextAreaElement>) => handleChange('chief_complain', e.target.value)}
                                    placeholder="Patient's main concern or reason for seeking treatment..."
                                />
                            </div>

                            <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                                <label htmlFor="dx-diagnosis">
                                    Diagnosis <span className={styles.required}>*</span>
                                </label>
                                <textarea
                                    id="dx-diagnosis"
                                    className={styles.formTextarea}
                                    rows={5}
                                    value={diagnosisData.diagnosis || ''}
                                    onChange={(e: ChangeEvent<HTMLTextAreaElement>) => handleChange('diagnosis', e.target.value)}
                                    placeholder="Complete orthodontic diagnosis (e.g., Class II Division 1 malocclusion, severe crowding, deep bite...)"
                                    required
                                />
                            </div>

                            <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                                <label htmlFor="dx-treatment-plan">
                                    Treatment Plan <span className={styles.required}>*</span>
                                </label>
                                <textarea
                                    id="dx-treatment-plan"
                                    className={styles.formTextarea}
                                    rows={5}
                                    value={diagnosisData.treatment_plan || ''}
                                    onChange={(e: ChangeEvent<HTMLTextAreaElement>) => handleChange('treatment_plan', e.target.value)}
                                    placeholder="Detailed treatment plan including extractions, mechanics, duration, etc..."
